import { 
  WeatherData, 
  ForecastData, 
  AQIData 
} from '../types';
import { 
  OPENWEATHER_API_KEY, 
  WAQI_API_KEY, 
  BASE_URL_OWM, 
  BASE_URL_WAQI 
} from '../constants';

export const fetchWeatherByCity = async (city: string): Promise<WeatherData> => {
  const response = await fetch(`${BASE_URL_OWM}weather?units=metric&q=${city}&appid=${OPENWEATHER_API_KEY}`);
  if (!response.ok) throw new Error("City not found");
  return response.json();
};

export const fetchWeatherByCoords = async (lat: number, lon: number): Promise<WeatherData> => {
  const response = await fetch(`${BASE_URL_OWM}weather?units=metric&lat=${lat}&lon=${lon}&appid=${OPENWEATHER_API_KEY}`);
  if (!response.ok) throw new Error("Location not found");
  return response.json();
};

export const fetchForecast = async (lat: number, lon: number): Promise<ForecastData> => {
  const response = await fetch(`${BASE_URL_OWM}forecast?units=metric&lat=${lat}&lon=${lon}&appid=${OPENWEATHER_API_KEY}`);
  if (!response.ok) throw new Error("Forecast data unavailable");
  return response.json();
};

export const fetchAQI = async (lat: number, lon: number): Promise<AQIData> => {
  const response = await fetch(`${BASE_URL_WAQI}feed/geo:${lat};${lon}/?token=${WAQI_API_KEY}`);
  const data = await response.json();
  if (data.status !== 'ok') throw new Error("AQI data unavailable");
  return data.data;
};

export const getHotspotData = async (): Promise<{ name: string; aqi: number }> => {
  const cities = [
    { name: 'Delhi', lat: 28.61, lon: 77.20 },
    { name: 'Beijing', lat: 39.90, lon: 116.40 },
    { name: 'Lahore', lat: 31.52, lon: 74.35 }
  ];
  let max = -1;
  let hotCity = { name: "N/A", aqi: 0 };

  for (const c of cities) {
    try {
      const data = await fetchAQI(c.lat, c.lon);
      if (data.aqi > max) {
        max = data.aqi;
        hotCity = { name: c.name, aqi: max };
      }
    } catch (e) {
      console.warn("Could not fetch hotspot data for", c.name);
    }
  }
  return hotCity;
};

import { GoogleGenAI } from "@google/genai";
import { WeatherData, AQIData } from "../types";

export const getWeatherInsight = async (weather: WeatherData, aqi: AQIData): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
  const prompt = `
    Analyze the current weather and air quality for ${weather.name}, ${weather.sys.country}.
    Weather: ${weather.weather[0].description}, Temp: ${Math.round(weather.main.temp)}°C, Humidity: ${weather.main.humidity}%.
    Air Quality Index: ${aqi.aqi}.
    Provide a concise, friendly 2-sentence summary and 1 practical recommendation for outdoor activities.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "No insights available at the moment.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "The sky is the limit! Enjoy your day.";
  }
};

import React, { useEffect, useRef } from 'react';
import { OPENWEATHER_API_KEY } from '../constants';

interface MapDisplayProps {
  lat: number;
  lon: number;
  cityName: string;
}

const MapDisplay: React.FC<MapDisplayProps> = ({ lat, lon, cityName }) => {
  const mapRef = useRef<L.Map | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!containerRef.current) return;

    if (!mapRef.current) {
      // @ts-ignore
      mapRef.current = L.map(containerRef.current, { zoomControl: false }).setView([lat, lon], 10);

      // @ts-ignore
      L.tileLayer('https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}', {
        maxZoom: 18
      }).addTo(mapRef.current);

      // @ts-ignore
      L.tileLayer('https://{s}.basemaps.cartocdn.com/rastertiles/voyager_only_labels/{z}/{x}/{y}{r}.png', {
        subdomains: 'abcd',
        maxZoom: 18
      }).addTo(mapRef.current);

      // Precipitation layer
      // @ts-ignore
      L.tileLayer(`https://tile.openweathermap.org/map/precipitation_new/{z}/{x}/{y}.png?appid=${OPENWEATHER_API_KEY}`, {
        opacity: 0.6
      }).addTo(mapRef.current);
    } else {
      mapRef.current.flyTo([lat, lon], 10);
    }

    return () => {
      // We don't necessarily want to destroy the map every re-render to save performance
    };
  }, [lat, lon]);

  return (
    <div className="relative w-full h-64 rounded-2xl overflow-hidden border border-white/20 mt-6 group">
      <div ref={containerRef} className="w-full h-full" />
      <div className="absolute bottom-4 left-4 z-[400] bg-black/60 backdrop-blur-md px-3 py-1 rounded-lg text-xs font-bold pointer-events-none">
        {cityName} Satellite Radar
      </div>
    </div>
  );
};

export default MapDisplay;

