interface AQIModalProps {
  isOpen: boolean;
  onClose: () => void;
  aqiData: AQIData;
  hotspot?: { name: string; aqi: number };
}

export const AQIModal: React.FC<AQIModalProps> = ({ isOpen, onClose, aqiData, hotspot }) => {
  if (!isOpen) return null;

  const getAQIStatus = (val: number) => {
    if (val <= 50) return { label: "Good", color: "#68d546", bg: "rgba(104, 213, 70, 0.1)" };
    if (val <= 100) return { label: "Moderate", color: "#fdd835", bg: "rgba(253, 216, 53, 0.1)" };
    if (val <= 150) return { label: "Poor", color: "#ff9800", bg: "rgba(255, 152, 0, 0.1)" };
    if (val <= 200) return { label: "Unhealthy", color: "#e91e63", bg: "rgba(233, 30, 99, 0.1)" };
    if (val <= 300) return { label: "Severe", color: "#9c27b0", bg: "rgba(156, 39, 176, 0.1)" };
    return { label: "Hazardous", color: "#b71c1c", bg: "rgba(183, 28, 28, 0.1)" };
  };

  const status = getAQIStatus(aqiData.aqi);
  const percentage = Math.min((aqiData.aqi / 350) * 100, 100);

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in duration-300">
      <div className="glass w-full max-w-lg rounded-3xl p-8 animate-in zoom-in-95 duration-300">
        <div className="flex justify-between items-center mb-8 border-b border-white/10 pb-4">
          <h2 className="text-xl font-bold text-orange-500 uppercase tracking-wider">Air Quality Index</h2>
          <button onClick={onClose} className="text-3xl hover:rotate-90 transition-transform">&times;</button>
        </div>

        <div className="space-y-8">
          <div className="flex justify-between items-start">
            <div>
              <div className="flex items-center gap-2 mb-1 text-xs font-bold text-orange-500">
                <span className="w-2 h-2 rounded-full bg-orange-500 animate-pulse" /> LIVE AQI
              </div>
              <div className="text-7xl font-extrabold" style={{ color: status.color }}>
                {aqiData.aqi}
                <span className="text-sm font-medium ml-2 opacity-50">AQI-US</span>
              </div>
            </div>
            <div className="text-right">
              <div className="text-xs opacity-60 mb-1">Air quality is</div>
              <div className="px-4 py-2 rounded-xl font-bold border" style={{ borderColor: status.color, color: status.color, backgroundColor: status.bg }}>
                {status.label}
              </div>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="bg-white/5 p-4 rounded-2xl flex justify-between items-center">
              <span className="text-xs opacity-60">PM10</span>
              <span className="font-bold">{aqiData.iaqi.pm10?.v || '--'} <span className="text-[10px] font-normal opacity-50">µg/m³</span></span>
            </div>
            <div className="bg-white/5 p-4 rounded-2xl flex justify-between items-center">
              <span className="text-xs opacity-60">PM2.5</span>
              <span className="font-bold">{aqiData.iaqi.pm25?.v || '--'} <span className="text-[10px] font-normal opacity-50">µg/m³</span></span>
            </div>
          </div>

          <div className="relative pt-6 pb-2">
             <div className="flex justify-between text-[8px] opacity-40 mb-1 px-1">
               <span>Good</span><span>Mod</span><span>Poor</span><span>Unhealthy</span><span>Sev</span><span>Haz</span>
             </div>
             <div className="h-2 w-full rounded-full bg-gradient-to-r from-green-500 via-yellow-500 via-orange-500 via-red-500 to-purple-900" />
             <div 
               className="absolute top-8 w-4 h-4 bg-white border-2 border-slate-900 rounded-full shadow-lg transition-all duration-1000"
               style={{ left: `calc(${percentage}% - 8px)` }}
             />
             <div className="flex justify-between text-[8px] opacity-40 mt-1 px-1">
               <span>0</span><span>50</span><span>100</span><span>150</span><span>200</span><span>300</span><span>301+</span>
             </div>
          </div>

          {hotspot && (
            <div className="bg-gradient-to-br from-red-900/40 to-pink-900/40 border border-white/10 rounded-2xl p-5 flex justify-between items-center">
              <div>
                <div className="text-[10px] font-bold text-red-400 mb-1 uppercase tracking-tighter flex items-center gap-1">
                  <i className="fas fa-exclamation-triangle" /> Global Hotspot
                </div>
                <div className="text-xl font-bold">{hotspot.name}</div>
              </div>
              <div className="text-right">
                <div className="text-2xl font-black text-red-400">{hotspot.aqi}</div>
                <div className="text-[10px] opacity-60">AQI</div>
              </div>
            </div>
          )}
