import React, { useState } from 'react';
import { User } from '../types';

interface LoginModalProps {
  isOpen: boolean;
  onClose: () => void;
  onLogin: (user: User) => void;
}

const LoginModal: React.FC<LoginModalProps> = ({ isOpen, onClose, onLogin }) => {
  const [nickname, setNickname] = useState('');
  const [email, setEmail] = useState('');
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);

  if (!isOpen) return null;

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (!nickname || !email) return alert("Please fill all fields");
    if (!email.includes("@")) return alert("Please enter a valid email");

    setLoading(true);
    setTimeout(() => {
      setLoading(false);
      setSuccess(true);
      setTimeout(() => {
        onLogin({ nickname, email });
        onClose();
      }, 1500);
    }, 2000);
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/80 backdrop-blur-xl animate-in fade-in duration-300">
      <div className="bg-slate-900 border border-white/10 w-full max-w-sm rounded-[32px] p-8 text-center relative animate-in zoom-in-95 duration-300">
        <button onClick={onClose} className="absolute top-6 right-6 text-2xl opacity-60 hover:opacity-100 hover:rotate-90 transition-all">&times;</button>

        {!loading && !success && (
          <div className="animate-in fade-in slide-in-from-bottom-4">
            <h2 className="text-3xl font-bold mb-2">Welcome</h2>
            <p className="text-sm opacity-50 mb-8">No password required. Just your nick and mail.</p>

            <form onSubmit={handleLogin} className="space-y-4">
              <input 
                type="text" 
                placeholder="Nickname" 
                className="w-full bg-white/5 border border-white/10 rounded-2xl px-5 py-4 outline-none focus:border-blue-500 transition-colors"
                value={nickname}
                onChange={(e) => setNickname(e.target.value)}
              />
              <input 
                type="email" 
                placeholder="Google Email" 
                className="w-full bg-white/5 border border-white/10 rounded-2xl px-5 py-4 outline-none focus:border-blue-500 transition-colors"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
              />
              <button className="w-full bg-blue-600 hover:bg-blue-700 py-4 rounded-2xl font-bold text-lg transition-all active:scale-95">
                Continue
              </button>
            </form>
          </div>
        )}

        {loading && (
          <div className="py-12 flex flex-col items-center animate-pulse">
            <div className="w-12 h-12 border-4 border-blue-500/20 border-t-blue-500 rounded-full animate-spin mb-4" />
            <p className="text-blue-400 font-medium">Verifying Account...</p>
          </div>
        )}

        {success && (
          <div className="py-12 flex flex-col items-center animate-in zoom-in duration-500">
            <div className="w-16 h-16 bg-green-500/20 text-green-500 rounded-full flex items-center justify-center text-3xl mb-4">
              <i className="fas fa-check" />
            </div>
            <p className="text-xl font-bold">Successfully Logged In!</p>
            <p className="text-sm opacity-50">Preparing your weather board...</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default LoginModal;

