import React, { useEffect, useRef } from 'react';
import { OPENWEATHER_API_KEY } from '../constants';

interface MapDisplayProps {
  lat: number;
  lon: number;
  cityName: string;
}

const MapDisplay: React.FC<MapDisplayProps> = ({ lat, lon, cityName }) => {
  // Use 'any' type for mapRef to resolve the missing 'L' namespace error
  const mapRef = useRef<any>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!containerRef.current) return;

    if (!mapRef.current) {
      // @ts-ignore
      mapRef.current = L.map(containerRef.current, { zoomControl: false }).setView([lat, lon], 10);

      // @ts-ignore
      L.tileLayer('https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}', {
        maxZoom: 18
      }).addTo(mapRef.current);

      // @ts-ignore
      L.tileLayer('https://{s}.basemaps.cartocdn.com/rastertiles/voyager_only_labels/{z}/{x}/{y}{r}.png', {
        subdomains: 'abcd',
        maxZoom: 18
      }).addTo(mapRef.current);

      // Precipitation layer
      // @ts-ignore
      L.tileLayer(`https://tile.openweathermap.org/map/precipitation_new/{z}/{x}/{y}.png?appid=${OPENWEATHER_API_KEY}`, {
        opacity: 0.6
      }).addTo(mapRef.current);
    } else {
      mapRef.current.flyTo([lat, lon], 10);
    }

    return () => {
      // We don't necessarily want to destroy the map every re-render to save performance
    };
  }, [lat, lon]);

  return (
    <div className="relative w-full h-64 rounded-2xl overflow-hidden border border-white/20 mt-6 group">
      <div ref={containerRef} className="w-full h-full" />
      <div className="absolute bottom-4 left-4 z-[400] bg-black/60 backdrop-blur-md px-3 py-1 rounded-lg text-xs font-bold pointer-events-none">
        {cityName} Satellite Radar
      </div>
    </div>
  );
};

export default MapDisplay;

import { GoogleGenAI } from "@google/genai";
import { WeatherData, AQIData } from "../types";

export const getWeatherInsight = async (weather: WeatherData, aqi: AQIData): Promise<string> => {
  // Initialize the AI client using a named parameter with process.env.API_KEY directly as per guidelines
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `
    Analyze the current weather and air quality for ${weather.name}, ${weather.sys.country}.
    Weather: ${weather.weather[0].description}, Temp: ${Math.round(weather.main.temp)}°C, Humidity: ${weather.main.humidity}%.
    Air Quality Index: ${aqi.aqi}.
    Provide a concise, friendly 2-sentence summary and 1 practical recommendation for outdoor activities.
  `;

  try {
    // Generate content using the recommended model for basic text analysis tasks
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    // Use the .text property directly as it is a getter (not a method)
    return response.text || "No insights available at the moment.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "The sky is the limit! Enjoy your day.";
  }
};

