          <div className="flex justify-between items-start">
            <div>
              <div className="flex items-center gap-2 mb-1 text-xs font-bold text-orange-500">
                <span className="w-2 h-2 rounded-full bg-orange-500 animate-pulse" /> OWM LEVEL
              </div>
              <div className="text-7xl font-extrabold" style={{ color: status.color }}>
                {aqiData.aqi}
                <span className="text-sm font-medium ml-2 opacity-50">/ 5</span>
              </div>
            </div>
            <div className="text-right">
              <div className="text-xs opacity-60 mb-1">Status</div>
              <div className="px-4 py-2 rounded-xl font-bold border" style={{ borderColor: status.color, color: status.color, backgroundColor: status.bg }}>
