import React, { useEffect, useRef, useState } from 'react';
import { OPENWEATHER_API_KEY } from '../constants';

interface MapDisplayProps {
  lat: number;
  lon: number;
  cityName: string;
}

type MapLayer = 'satellite' | 'streets' | 'terrain';

interface RadarFrame {
  time: number;
  path: string;
}

const MapDisplay: React.FC<MapDisplayProps> = ({ lat, lon, cityName }) => {
  const mapRef = useRef<any>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const [activeLayer, setActiveLayer] = useState<MapLayer>('satellite');
  const layersRef = useRef<Record<string, any>>({});

  // Radar Animation State
  const [radarFrames, setRadarFrames] = useState<RadarFrame[]>([]);
  const [activeFrameIndex, setActiveFrameIndex] = useState(-1);
  const [isPlaying, setIsPlaying] = useState(false);
  const radarLayersRef = useRef<any[]>([]);
  const animationIntervalRef = useRef<number | null>(null);

  const layerConfigs = {
    satellite: {
      url: 'https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}',
      attribution: 'Esri, DigitalGlobe, GeoEye, Earthstar Geographics'
    },
    streets: {
      url: 'https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png',
      attribution: '&copy; OpenStreetMap contributors &copy; CARTO'
    },
    terrain: {
      url: 'https://server.arcgisonline.com/ArcGIS/rest/services/World_Topo_Map/MapServer/tile/{z}/{y}/{x}',
      attribution: 'Esri, HERE, Garmin, Intermap'
    }
  };

  // 1. Initialize Map
  useEffect(() => {
    if (!containerRef.current) return;

    if (!mapRef.current) {
      // @ts-ignore
      mapRef.current = L.map(containerRef.current, { 
        zoomControl: false,
        attributionControl: false 
      }).setView([lat, lon], 10);

      updateBaseLayer('satellite');
      fetchRadarFrames();
    } else {
      mapRef.current.flyTo([lat, lon], 10);
    }

    return () => {
      if (animationIntervalRef.current) window.clearInterval(animationIntervalRef.current);
    };
  }, [lat, lon]);

  // 2. Fetch Radar Timestamps from RainViewer (Standard for Animation)
  const fetchRadarFrames = async () => {
    try {
      const response = await fetch('https://api.rainviewer.com/public/weather-maps.json');
      const data = await response.json();
      const frames: RadarFrame[] = data.radar.past.map((f: any) => ({
        time: f.time,
        path: f.path
      }));
      setRadarFrames(frames);
      setActiveFrameIndex(frames.length - 1); // Start with most recent
    } catch (error) {
      console.error("Failed to fetch radar frames:", error);
    }
  };

  // 3. Update Base Tile Layer
  const updateBaseLayer = (layerType: MapLayer) => {
    if (!mapRef.current) return;
    Object.values(layersRef.current).forEach(layer => mapRef.current.removeLayer(layer));

    // @ts-ignore
    const newLayer = L.tileLayer(layerConfigs[layerType].url, {
      maxZoom: 18,
      attribution: layerConfigs[layerType].attribution
    });

    newLayer.addTo(mapRef.current);
    layersRef.current[layerType] = newLayer;

    if (layerType === 'satellite') {
      // @ts-ignore
      const labels = L.tileLayer('https://{s}.basemaps.cartocdn.com/rastertiles/voyager_only_labels/{z}/{x}/{y}{r}.png', {
        subdomains: 'abcd',
        maxZoom: 18,
        zIndex: 50
      });
      labels.addTo(mapRef.current);
      layersRef.current['labels'] = labels;
    }
  };

  useEffect(() => {
    updateBaseLayer(activeLayer);
  }, [activeLayer]);

  // 4. Manage Radar Layers Animation
  useEffect(() => {
    if (!mapRef.current || radarFrames.length === 0) return;

    // Clear existing radar layers
    radarLayersRef.current.forEach(layer => mapRef.current.removeLayer(layer));
    radarLayersRef.current = [];

    // Pre-load all frames but keep them hidden (opacity 0)
    radarFrames.forEach((frame, idx) => {
      // @ts-ignore
      const layer = L.tileLayer(`https://tilecache.rainviewer.com${frame.path}/256/{z}/{x}/{y}/2/1_1.png`, {
        opacity: 0,
        zIndex: 100 + idx
      }).addTo(mapRef.current);
      radarLayersRef.current[idx] = layer;
    });

    // Initial show
    if (activeFrameIndex !== -1 && radarLayersRef.current[activeFrameIndex]) {
      radarLayersRef.current[activeFrameIndex].setOpacity(0.6);
    }
  }, [radarFrames]);

  // 5. Handle Animation Interval
  useEffect(() => {
    if (isPlaying) {
      animationIntervalRef.current = window.setInterval(() => {
        setActiveFrameIndex((prev) => (prev + 1) % radarFrames.length);
      }, 600);
    } else {
      if (animationIntervalRef.current) window.clearInterval(animationIntervalRef.current);
    }
    return () => {
      if (animationIntervalRef.current) window.clearInterval(animationIntervalRef.current);
    };
  }, [isPlaying, radarFrames.length]);

  // 6. Update Visible Frame
  useEffect(() => {
    radarLayersRef.current.forEach((layer, idx) => {
      if (layer) layer.setOpacity(idx === activeFrameIndex ? 0.6 : 0);
    });
  }, [activeFrameIndex]);

  const formatTime = (ts: number) => {
    return new Date(ts * 1000).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  return (
    <div className="relative w-full h-80 rounded-[32px] overflow-hidden border border-white/20 mt-6 group bg-slate-800">
      <div ref={containerRef} className="w-full h-full" />

      {/* City Label */}
      <div className="absolute top-4 left-4 z-[400] bg-black/60 backdrop-blur-md px-3 py-1.5 rounded-xl text-[10px] font-bold pointer-events-none uppercase tracking-widest flex items-center gap-2 border border-white/10">
        <span className="w-1.5 h-1.5 rounded-full bg-orange-500 animate-pulse" />
        {cityName} RADAR
      </div>

      {/* Layer Switcher */}
      <div className="absolute top-4 right-4 z-[400] flex flex-col gap-2">
        {(['satellite', 'streets', 'terrain'] as MapLayer[]).map((layer) => (
          <button
            key={layer}
            onClick={() => setActiveLayer(layer)}
            className={`w-10 h-10 rounded-xl flex items-center justify-center transition-all duration-300 border backdrop-blur-md shadow-lg
              ${activeLayer === layer 
                ? 'bg-orange-600 border-orange-400 text-white scale-110' 
                : 'bg-black/40 border-white/10 text-white/60 hover:bg-black/60 hover:text-white'
              }`}
          >
            <i className={`fas ${
              layer === 'satellite' ? 'fa-globe' : 
              layer === 'streets' ? 'fa-road' : 'fa-mountain'
            }`} />
          </button>
        ))}
      </div>

      {/* Radar Animation Player Bar */}
      {radarFrames.length > 0 && (
        <div className="absolute bottom-4 left-4 right-4 z-[400] glass border-white/10 rounded-2xl p-3 flex items-center gap-4 animate-in slide-in-from-bottom-2 duration-500">
          <button 
            onClick={() => setIsPlaying(!isPlaying)}
            className="w-10 h-10 bg-orange-600 hover:bg-orange-500 rounded-xl flex items-center justify-center transition-all shrink-0 shadow-lg active:scale-95"
          >
            <i className={`fas ${isPlaying ? 'fa-pause' : 'fa-play'} text-sm`} />
          </button>

          <div className="flex-1 flex flex-col gap-1.5">
            <div className="flex justify-between items-center text-[10px] font-bold tracking-tighter uppercase">
              <span className="text-orange-500">Animation Loop</span>
              <span className="opacity-60">{formatTime(radarFrames[activeFrameIndex]?.time)}</span>
            </div>

            <div className="relative h-1.5 bg-white/10 rounded-full overflow-hidden">
              <div 
                className="absolute top-0 left-0 h-full bg-orange-500 transition-all duration-200"
                style={{ width: `${((activeFrameIndex + 1) / radarFrames.length) * 100}%` }}
              />
              <input 
                type="range"
                min="0"
                max={radarFrames.length - 1}
                value={activeFrameIndex}
                onChange={(e) => {
                  setIsPlaying(false);
                  setActiveFrameIndex(parseInt(e.target.value));
                }}
                className="absolute inset-0 w-full opacity-0 cursor-pointer"
              />
            </div>
          </div>

          <div className="hidden sm:flex flex-col items-end text-[10px] font-bold opacity-40 uppercase tracking-widest shrink-0">
            <span>Past 2h</span>
            <span>Frames: {radarFrames.length}</span>
          </div>
        </div>
      )}
    </div>
  );
};

export default MapDisplay;

import React, { useState, useEffect, useCallback } from 'react';
import Background from './components/Background';
import MapDisplay from './components/MapDisplay';
import LoginModal from './components/Auth';
import { ForecastModal, AQIModal } from './components/ForecastModals';
import { 
  fetchWeatherByCity, 
  fetchWeatherByCoords, 
  fetchForecast, 
  fetchAQI, 
  fetchUVIndex,
  getHotspotData 
} from './services/weatherService';
import { getWeatherInsight } from './services/geminiService';
import { 
  WeatherData, 
  ForecastData, 
  AQIData, 
  User, 
  ViewMode 
} from './types';
import { COLORS } from './constants';

const App: React.FC = () => {
  // UI State
  const [viewMode, setViewMode] = useState<ViewMode>('auto');
  const [isLoginOpen, setIsLoginOpen] = useState(false);
  const [isHourlyOpen, setIsHourlyOpen] = useState(false);
  const [isDailyOpen, setIsDailyOpen] = useState(false);
  const [isAQIOpen, setIsAQIOpen] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isContactOpen, setIsContactOpen] = useState(false);

  // Data State
  const [searchQuery, setSearchQuery] = useState('');
  const [weather, setWeather] = useState<WeatherData | null>(null);
  const [forecast, setForecast] = useState<ForecastData | null>(null);
  const [aqi, setAqi] = useState<AQIData | null>(null);
  const [uv, setUv] = useState<number | null>(null);
  const [hotspot, setHotspot] = useState<{ name: string; aqi: number } | undefined>();
  const [aiInsight, setAiInsight] = useState<string>('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Auth State
  const [user, setUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('rx_user');
    return saved ? JSON.parse(saved) : null;
  });
  const [history, setHistory] = useState<string[]>(() => {
    const saved = localStorage.getItem('rx_history');
    return saved ? JSON.parse(saved) : [];
  });
  const [showHistory, setShowHistory] = useState(false);

  // Time state
  const [currentTime, setCurrentTime] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const getUVStatus = (val: number) => {
    if (val <= 2) return { label: "Low", color: "text-green-400" };
    if (val <= 5) return { label: "Mod", color: "text-yellow-400" };
    if (val <= 7) return { label: "High", color: "text-orange-400" };
    if (val <= 10) return { label: "Very High", color: "text-red-400" };
    return { label: "Extreme", color: "text-purple-500" };
  };

  const handleSearch = useCallback(async (query: string) => {
    if (!query) return;
    setLoading(true);
    setError(null);
    setShowHistory(false);
    try {
      const weatherData = await fetchWeatherByCity(query);
      const [forecastData, aqiData, uvValue] = await Promise.all([
        fetchForecast(weatherData.coord.lat, weatherData.coord.lon),
        fetchAQI(weatherData.coord.lat, weatherData.coord.lon),
        fetchUVIndex(weatherData.coord.lat, weatherData.coord.lon)
      ]);

      setWeather(weatherData);
      setForecast(forecastData);
      setAqi(aqiData);
      setUv(uvValue);

      // AI Insight - non blocking
      getWeatherInsight(weatherData, aqiData, uvValue).then(setAiInsight);

      // Save History
      if (user) {
        setHistory(prev => {
          const updated = [weatherData.name, ...prev.filter(i => i !== weatherData.name)].slice(0, 5);
          localStorage.setItem('rx_history', JSON.stringify(updated));
          return updated;
        });
      }
    } catch (err: any) {
      setError(err.message || "Failed to fetch weather data");
    } finally {
      setLoading(false);
    }
  }, [user]);

  const handleLocationSearch = useCallback(() => {
    if (!navigator.geolocation) return alert("Geolocation not supported");

    setLoading(true);
    navigator.geolocation.getCurrentPosition(async (pos) => {
      try {
        const weatherData = await fetchWeatherByCoords(pos.coords.latitude, pos.coords.longitude);
        const [forecastData, aqiData, uvValue] = await Promise.all([
          fetchForecast(weatherData.coord.lat, weatherData.coord.lon),
          fetchAQI(weatherData.coord.lat, weatherData.coord.lon),
          fetchUVIndex(weatherData.coord.lat, weatherData.coord.lon)
        ]);
        setWeather(weatherData);
        setForecast(forecastData);
        setAqi(aqiData);
        setUv(uvValue);
        getWeatherInsight(weatherData, aqiData, uvValue).then(setAiInsight);
      } catch (err: any) {
        setError(err.message);
      } finally {
        setLoading(false);
      }
    }, (err) => {
      setLoading(false);
      setError("Location permission denied");
    });
  }, []);

  useEffect(() => {
    handleSearch("London"); // Default city
    getHotspotData().then(setHotspot);
  }, []);

  const toggleView = () => {
    const modes: ViewMode[] = ['auto', 'mobile', 'pc'];
    const next = modes[(modes.indexOf(viewMode) + 1) % 3];
    setViewMode(next);
  };

  const handleLogin = (newUser: User) => {
    setUser(newUser);
    localStorage.setItem('rx_user', JSON.stringify(newUser));
  };

  return (
    <div className={`min-h-screen p-4 flex items-center justify-center transition-all duration-500 ${viewMode === 'mobile' ? 'max-w-md mx-auto' : ''}`}>
      <Background />

      {/* Nav Buttons */}
      <div className="fixed top-6 left-6 flex gap-3 z-50">
        <button 
          onClick={() => setIsMenuOpen(!isMenuOpen)}
          className="w-12 h-12 glass rounded-full flex items-center justify-center hover:bg-orange-600 hover:scale-110 active:scale-90 transition-all duration-300 shadow-lg shadow-black/20"
        >
          <i className={`fas ${isMenuOpen ? 'fa-times' : 'fa-ellipsis-v'} transition-transform duration-300 ${isMenuOpen ? 'rotate-90' : ''}`} />
        </button>

        <button 
          onClick={() => user ? null : setIsLoginOpen(true)}
          className={`px-6 h-12 glass rounded-full flex items-center gap-2 font-bold text-sm transition-all duration-300 shadow-lg shadow-black/20 ${user ? 'border-green-500/50 text-green-400' : 'hover:scale-105 active:scale-95 hover:bg-white/10'}`}
        >
          <i className={`fas ${user ? 'fa-user-check' : 'fa-user'} ${user ? 'animate-bounce' : ''}`} />
          {user ? user.nickname : 'Login'}
        </button>
      </div>

      <button 
        onClick={toggleView}
        className="fixed top-6 right-6 px-6 h-12 glass rounded-full flex items-center gap-2 font-bold text-sm uppercase tracking-tighter hover:scale-105 active:scale-95 transition-all duration-300 z-50 shadow-lg shadow-black/20 hover:bg-white/10"
      >
        <i className="fas fa-magic transition-transform group-hover:rotate-45" />
        {viewMode}
      </button>

      {/* Menu Dropdown */}
      {isMenuOpen && (
        <div className="fixed top-20 left-6 w-56 glass rounded-2xl p-2 z-50 animate-in fade-in slide-in-from-top-4 duration-300 shadow-2xl">
          <button 
            onClick={() => { setIsContactOpen(true); setIsMenuOpen(false); }}
            className="w-full text-left px-4 py-3 rounded-xl hover:bg-white/10 flex items-center gap-3 transition-all duration-200 hover:translate-x-1"
          >
            <i className="fas fa-envelope opacity-50 text-orange-500" /> Contact Us
          </button>
          {user && (
             <button 
             onClick={() => { setUser(null); localStorage.removeItem('rx_user'); setIsMenuOpen(false); }}
             className="w-full text-left px-4 py-3 rounded-xl hover:bg-red-500/20 text-red-400 flex items-center gap-3 transition-all duration-200 hover:translate-x-1"
           >
             <i className="fas fa-sign-out-alt opacity-50" /> Logout
           </button>
          )}
        </div>
      )}

      {/* Main Card */}
      <div className={`glass w-full max-w-2xl rounded-[40px] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-700 ${viewMode === 'pc' ? 'scale-110' : ''}`}>
        {/* Header */}
        <div className="bg-black/20 p-6 flex justify-between items-center border-b border-white/5">
          <div className="flex items-center gap-3 text-lg font-black tracking-widest uppercase">
            <i className="fas fa-cloud-sun text-orange-500 animate-pulse" /> RX WEATHER
          </div>
          <div className="text-right">
            <div className="text-[10px] font-bold opacity-60 uppercase tracking-widest">
              {currentTime.toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric' })}
            </div>
            <div className="text-xl font-bold font-mono">
              {currentTime.toLocaleTimeString('en-US', { hour12: true, hour: '2-digit', minute: '2-digit', second: '2-digit' })}
            </div>
          </div>
        </div>

        {/* Search */}
        <div className="p-8 pb-4 relative">
          <div className="flex gap-2 p-1.5 bg-white/5 border border-white/10 rounded-full focus-within:bg-black/40 focus-within:border-orange-500/50 transition-all duration-500 shadow-inner">
            <input 
              type="text" 
              placeholder="Search location..." 
              className="bg-transparent flex-1 px-6 outline-none text-lg placeholder:opacity-40"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              onFocus={() => setShowHistory(true)}
              onKeyDown={(e) => e.key === 'Enter' && handleSearch(searchQuery)}
            />
            <button 
              onClick={handleLocationSearch} 
              className="w-12 h-12 rounded-full hover:bg-green-500/20 hover:text-green-400 flex items-center justify-center transition-all duration-300 active:scale-90"
              title="Use current location"
            >
              <i className="fas fa-location-arrow" />
            </button>
            <button 
              onClick={() => handleSearch(searchQuery)} 
              className="w-12 h-12 bg-orange-600 rounded-full flex items-center justify-center hover:bg-orange-500 hover:rotate-90 hover:scale-110 active:scale-90 transition-all duration-500 shadow-lg shadow-orange-500/20"
            >
              <i className="fas fa-search" />
            </button>
          </div>

          {/* History dropdown */}
          {showHistory && user && history.length > 0 && (
            <div className="absolute top-24 left-10 right-10 glass rounded-2xl p-2 z-40 border-white/20 animate-in fade-in slide-in-from-top-1 shadow-2xl">
              {history.map((h, i) => (
                <button 
                  key={i} 
                  onClick={() => { setSearchQuery(h); handleSearch(h); }}
                  className="w-full text-left px-4 py-3 rounded-xl hover:bg-white/10 flex items-center justify-between group transition-all duration-200 hover:translate-x-1"
                >
                  <span className="flex items-center gap-3 text-sm font-medium"><i className="fas fa-history opacity-30 text-xs" /> {h}</span>
                  <i className="fas fa-arrow-right opacity-0 group-hover:opacity-30 transition-all duration-300 group-hover:translate-x-1" />
                </button>
              ))}
            </div>
          )}
        </div>

        {/* Content Area */}
        <div className="px-8 pb-8">
          {error && (
            <div className="bg-red-500/20 border-l-4 border-red-500 p-4 rounded-xl mb-4 animate-in shake-in">
              <span className="font-bold uppercase text-[10px] block mb-1">Error</span>
              {error}
            </div>
          )}

