      <div className="fixed top-6 left-6 flex gap-3 z-50">
        <button 
          onClick={() => setIsMenuOpen(!isMenuOpen)}
          className="w-12 h-12 glass rounded-full flex items-center justify-center hover:bg-orange-600 hover:scale-110 active:scale-90 transition-all duration-300 shadow-lg shadow-black/20"
        >
          <i className={`fas ${isMenuOpen ? 'fa-times' : 'fa-ellipsis-v'} transition-transform duration-300 ${isMenuOpen ? 'rotate-90' : ''}`} />
        </button>

        <button 
          onClick={() => user ? null : setIsLoginOpen(true)}
          className={`px-6 h-12 glass rounded-full flex items-center gap-2 font-bold text-sm transition-all duration-300 shadow-lg shadow-black/20 ${user ? 'border-green-500/50 text-green-400' : 'hover:scale-105 active:scale-95 hover:bg-white/10'}`}
        >
          <i className={`fas ${user ? 'fa-user-check' : 'fa-user'} ${user ? 'animate-bounce' : ''}`} />
          {user ? user.nickname : 'Login'}
        </button>
      </div>

      <button 
        onClick={toggleView}
        className="fixed top-6 right-6 px-6 h-12 glass rounded-full flex items-center gap-2 font-bold text-sm uppercase tracking-tighter hover:scale-105 active:scale-95 transition-all duration-300 z-50 shadow-lg shadow-black/20 hover:bg-white/10"
      >
        <i className="fas fa-magic transition-transform group-hover:rotate-45" />
        {viewMode}
      </button>

      {/* Menu Dropdown */}
      {isMenuOpen && (
        <div className="fixed top-20 left-6 w-56 glass rounded-2xl p-2 z-50 animate-in fade-in slide-in-from-top-4 duration-300 shadow-2xl">
          <button 
            onClick={() => { setIsContactOpen(true); setIsMenuOpen(false); }}
            className="w-full text-left px-4 py-3 rounded-xl hover:bg-white/10 flex items-center gap-3 transition-all duration-200 hover:translate-x-1"
          >
            <i className="fas fa-envelope opacity-50 text-orange-500" /> Contact Us
          </button>
          {user && (
             <button 
             onClick={() => { setUser(null); localStorage.removeItem('rx_user'); setIsMenuOpen(false); }}
             className="w-full text-left px-4 py-3 rounded-xl hover:bg-red-500/20 text-red-400 flex items-center gap-3 transition-all duration-200 hover:translate-x-1"
           >
             <i className="fas fa-sign-out-alt opacity-50" /> Logout
           </button>
          )}
        </div>
      )}

      {/* Main Card */}
      <div className={`glass w-full max-w-2xl rounded-[40px] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-700 ${viewMode === 'pc' ? 'scale-110' : ''}`}>
        {/* Header */}
        <div className="bg-black/20 p-6 flex justify-between items-center border-b border-white/5">
          <div className="flex items-center gap-3 text-lg font-black tracking-widest uppercase">
            <i className="fas fa-cloud-sun text-orange-500 animate-pulse" /> RX WEATHER
          </div>
          <div className="text-right">
            <div className="text-[10px] font-bold opacity-60 uppercase tracking-widest">
              {currentTime.toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric' })}
            </div>
            <div className="text-xl font-bold font-mono">
              {currentTime.toLocaleTimeString('en-US', { hour12: true, hour: '2-digit', minute: '2-digit', second: '2-digit' })}
            </div>
          </div>
        </div>

        {/* Search */}
        <div className="p-8 pb-4 relative">
          <div className="flex gap-2 p-1.5 bg-white/5 border border-white/10 rounded-full focus-within:bg-black/40 focus-within:border-orange-500/50 transition-all duration-500 shadow-inner">
            <input 
              type="text" 
              placeholder="Search location..." 
              className="bg-transparent flex-1 px-6 outline-none text-lg placeholder:opacity-40"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              onFocus={() => setShowHistory(true)}
              onKeyDown={(e) => e.key === 'Enter' && handleSearch(searchQuery)}
            />
            {/* Prominent Refresh Button */}
            <button 
              onClick={() => weather && handleSearch(weather.name)} 
              className={`w-12 h-12 rounded-full hover:bg-blue-500/20 hover:text-blue-400 flex items-center justify-center transition-all duration-300 active:scale-90 ${loading ? 'pointer-events-none opacity-40' : ''}`}
              title="Refresh current weather"
              disabled={loading || !weather}
            >
              <i className={`fas fa-sync-alt ${loading ? 'animate-spin' : ''}`} />
            </button>
            <button 
              onClick={handleLocationSearch} 
              className="w-12 h-12 rounded-full hover:bg-green-500/20 hover:text-green-400 flex items-center justify-center transition-all duration-300 active:scale-90"
              title="Use current location"
            >
              <i className="fas fa-location-arrow" />
            </button>
            <button 
              onClick={() => handleSearch(searchQuery)} 
              className="w-12 h-12 bg-orange-600 rounded-full flex items-center justify-center hover:bg-orange-500 hover:rotate-90 hover:scale-110 active:scale-90 transition-all duration-500 shadow-lg shadow-orange-500/20"
            >
              <i className="fas fa-search" />
            </button>
          </div>

          {/* History dropdown */}
          {showHistory && user && history.length > 0 && (
            <div className="absolute top-24 left-10 right-10 glass rounded-2xl p-2 z-40 border-white/20 animate-in fade-in slide-in-from-top-1 shadow-2xl">
              {history.map((h, i) => (
                <button 
                  key={i} 
                  onClick={() => { setSearchQuery(h); handleSearch(h); }}
                  className="w-full text-left px-4 py-3 rounded-xl hover:bg-white/10 flex items-center justify-between group transition-all duration-200 hover:translate-x-1"
                >
                  <span className="flex items-center gap-3 text-sm font-medium"><i className="fas fa-history opacity-30 text-xs" /> {h}</span>
                  <i className="fas fa-arrow-right opacity-0 group-hover:opacity-30 transition-all duration-300 group-hover:translate-x-1" />
                </button>
              ))}
            </div>
          )}
        </div>

        {/* Content Area */}
        <div className="px-8 pb-8">
          {error && (
            <div className="bg-red-500/20 border-l-4 border-red-500 p-4 rounded-xl mb-4 animate-in shake-in">
              <span className="font-bold uppercase text-[10px] block mb-1">Error</span>
              {error}
            </div>
          )}

          {weather && !loading ? (
            <div className="animate-in fade-in slide-in-from-bottom-4 duration-700">
              <div className="grid md:grid-cols-2 gap-8 items-center border-b border-white/10 pb-8">
                {/* Left: Main Weather */}
                <div className="flex flex-col">
                  <div className="flex items-center gap-4">
                    <img src={`https://openweathermap.org/img/wn/${weather.weather[0].icon}@4x.png`} className="w-24 h-24 drop-shadow-2xl animate-[float_4s_ease-in-out_infinite]" alt="icon" />
                    <div>
                      <div className="text-7xl font-bold tracking-tighter">{Math.round(weather.main.temp)}<span className="text-3xl font-light align-top mt-2 inline-block">°C</span></div>
                      <div className="text-sm font-medium opacity-60">RealFeel® {Math.round(weather.main.feels_like)}°</div>
                    </div>
                  </div>
                  <div className="text-2xl font-bold mt-4 flex items-center gap-2 group cursor-default">
                    <i className="fas fa-map-marker-alt text-orange-500 transition-transform group-hover:scale-125" />
                    {weather.name}, {weather.sys.country}
                  </div>
                </div>

                {/* Right: Details */}
                <div className="space-y-3">
                  {[
                    { label: "Today's Low", val: `${Math.round(weather.main.temp_min)}°C` },
                    { label: "Wind Speed", val: `${Math.round(weather.wind.speed * 3.6)} km/h` },
                    { label: "Humidity", val: `${weather.main.humidity}%` },
                    { label: "Pressure", val: `${weather.main.pressure} mb` },
                    { label: "UV Index", val: uv !== null ? (
                      <span className="flex items-center gap-2">
                        {Math.round(uv)} 
                        <span className={`text-[10px] font-bold uppercase px-2 py-0.5 rounded-full bg-white/10 ${getUVStatus(uv).color} animate-pulse`}>
                          {getUVStatus(uv).label}
                        </span>
                      </span>
                    ) : '--' },
                  ].map((d, i) => (
                    <div key={i} className="flex justify-between items-center py-2 border-b border-white/5 last:border-0 hover:bg-white/5 transition-colors px-2 -mx-2 rounded-lg">
                      <span className="text-sm opacity-50 font-medium">{d.label}</span>
                      <span className="font-bold flex items-center text-sm">{d.val}</span>
                    </div>
                  ))}
                </div>
              </div>

              {/* AI Insight Box */}
              {aiInsight && (
                <div className="mt-6 p-5 bg-gradient-to-r from-blue-600/20 to-purple-600/20 border border-white/10 rounded-2xl flex items-start gap-4 group transition-all duration-300 hover:scale-[1.02] hover:shadow-xl hover:shadow-blue-500/10">
                  <div className="w-10 h-10 bg-white/10 rounded-xl flex items-center justify-center shrink-0 group-hover:bg-blue-600 transition-colors">
                    <i className="fas fa-robot text-blue-400 group-hover:text-white transition-colors" />
                  </div>
                  <div className="text-sm italic opacity-90 leading-relaxed">
                    <span className="font-bold text-blue-300 not-italic block mb-1 text-[10px] tracking-widest">AI INTELLIGENCE</span>
                    "{aiInsight}"
                  </div>
                </div>
              )}

              {/* Actions */}
              <div className="grid grid-cols-3 gap-3 mt-6">
                <button onClick={() => setIsHourlyOpen(true)} className="glass py-3.5 rounded-2xl text-[10px] font-black uppercase hover:bg-orange-600 hover:scale-105 active:scale-95 transition-all duration-300 shadow-lg hover:shadow-orange-500/20 tracking-widest">Hourly</button>
                <button onClick={() => setIsDailyOpen(true)} className="glass py-3.5 rounded-2xl text-[10px] font-black uppercase hover:bg-orange-600 hover:scale-105 active:scale-95 transition-all duration-300 shadow-lg hover:shadow-orange-500/20 tracking-widest">Daily</button>
                <button onClick={() => setIsAQIOpen(true)} className="glass py-3.5 rounded-2xl text-[10px] font-black uppercase hover:bg-orange-600 hover:scale-105 active:scale-95 transition-all duration-300 shadow-lg hover:shadow-orange-500/20 tracking-widest">AQI Detail</button>
              </div>

              <MapDisplay lat={weather.coord.lat} lon={weather.coord.lon} cityName={weather.name} />
            </div>
          ) : (
            <div className="py-24 flex flex-col items-center gap-6">
              <div className="relative">
                <div className="w-16 h-16 border-4 border-white/10 border-t-orange-500 rounded-full animate-spin" />
                <div className="absolute inset-0 flex items-center justify-center">
                  <i className="fas fa-satellite-dish text-orange-500 animate-pulse text-xs" />
                </div>
              </div>
              <p className="opacity-50 text-xs font-bold uppercase tracking-[0.2em] animate-pulse">Establishing uplink...</p>
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="bg-black/30 p-8 text-center space-y-2 border-t border-white/5">
          <div className="text-sm opacity-80 font-medium">Powered by <span className="font-black text-orange-500 hover:text-orange-400 cursor-help transition-colors">RX ENTERTAINMENT</span></div>
          <div className="text-[10px] opacity-30 uppercase tracking-[0.3em] font-bold">&copy; 2026 RX Weather. Engineered by Aman.</div>
          <div className="text-xs font-black text-cyan-400 animate-pulse tracking-[0.4em] pt-4">MADE WITH LOVE BY AMAN</div>
        </div>
      </div>

      {/* Social Sticky */}
      <a 
        href="https://www.instagram.com/aman_devv/" 
        target="_blank" 
        rel="noreferrer"
        className="fixed bottom-8 right-8 w-14 h-14 glass rounded-full flex items-center justify-center text-3xl group transition-all duration-500 hover:scale-125 hover:rotate-6 active:scale-90 shadow-2xl hover:shadow-pink-500/20"
      >
        <i className="fab fa-instagram bg-gradient-to-tr from-[#f09433] via-[#dc2743] to-[#bc1888] bg-clip-text text-transparent group-hover:scale-110 transition-all duration-300" />
      </a>

      {/* Modals */}
      <LoginModal 
        isOpen={isLoginOpen} 
        onClose={() => setIsLoginOpen(false)} 
        onLogin={handleLogin} 
      />

      {forecast && (
        <>
          <ForecastModal 
            isOpen={isHourlyOpen} 
            onClose={() => setIsHourlyOpen(false)} 
            items={forecast.list.slice(0, 8)} 
            title="Next 24 Hours"
            type="hourly"
          />
          <ForecastModal 
            isOpen={isDailyOpen} 
            onClose={() => setIsDailyOpen(false)} 
            items={forecast.list.filter((_, i) => i % 8 === 0)} 
            title="5-Day Outlook"
            type="daily"
          />
        </>
      )}

      {aqi && (
        <AQIModal 
          isOpen={isAQIOpen} 
          onClose={() => setIsAQIOpen(false)} 
          aqiData={aqi} 
          hotspot={hotspot}
        />
      )}

      {/* Contact Slider */}
      {isContactOpen && (
        <div className="fixed inset-0 z-[200] flex animate-in slide-in-from-left duration-700">
          <div className="w-80 h-full bg-gradient-to-br from-indigo-900 to-purple-950 p-12 flex flex-col justify-center relative shadow-[50px_0_100px_rgba(0,0,0,0.5)] border-r border-white/10">
            <button 
              onClick={() => setIsContactOpen(false)} 
              className="absolute top-8 right-8 text-3xl opacity-40 hover:opacity-100 hover:rotate-90 hover:scale-125 transition-all duration-300 active:scale-90"
            >
              &times;
            </button>
            <h2 className="text-4xl font-black mb-2 tracking-tighter">Get In Touch</h2>
            <p className="text-xs opacity-50 mb-10 font-bold uppercase tracking-widest">Support & Inquiries</p>

            <div className="space-y-4">
              <div className="bg-black/30 p-5 rounded-2xl border border-white/5 font-mono text-xs break-all hover:border-orange-500/30 transition-colors">
                sdfre3511@gmail.com
              </div>
              <button 
                onClick={() => { navigator.clipboard.writeText("sdfre3511@gmail.com"); alert("Email copied!"); }}
                className="w-full bg-white text-indigo-950 py-4 rounded-2xl font-black uppercase text-xs tracking-[0.2em] hover:scale-105 active:scale-95 hover:bg-orange-500 hover:text-white transition-all duration-300 shadow-xl"
              >
                Copy Email
              </button>
            </div>

            <div className="mt-auto pt-10 text-[10px] opacity-20 font-bold uppercase tracking-[0.3em]">
              Responsive Support 24/7
            </div>
          </div>
          <div className="flex-1 bg-black/40 backdrop-blur-md animate-in fade-in duration-700" onClick={() => setIsContactOpen(false)} />
        </div>
      )}

      <style>{`
        @keyframes float {
          0%, 100% { transform: translateY(0) rotate(0); }
          50% { transform: translateY(-10px) rotate(2deg); }
        }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback } from 'react';
import Background from './components/Background';
import MapDisplay from './components/MapDisplay';
import LoginModal from './components/Auth';
import { ForecastModal, AQIModal } from './components/ForecastModals';
import { 
  fetchWeatherByCity, 
  fetchWeatherByCoords, 
  fetchForecast, 
  fetchAQI, 
  fetchUVIndex,
  getHotspotData 
} from './services/weatherService';
import { getWeatherInsight } from './services/geminiService';
import { 
  WeatherData, 
  ForecastData, 
  AQIData, 
  User, 
  ViewMode 
} from './types';
import { COLORS } from './constants';

const App: React.FC = () => {
  // UI State
  const [viewMode, setViewMode] = useState<ViewMode>('auto');
  const [isLoginOpen, setIsLoginOpen] = useState(false);
  const [isHourlyOpen, setIsHourlyOpen] = useState(false);
  const [isDailyOpen, setIsDailyOpen] = useState(false);
  const [isAQIOpen, setIsAQIOpen] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isContactOpen, setIsContactOpen] = useState(false);

  // Data State
  const [searchQuery, setSearchQuery] = useState('');
  const [weather, setWeather] = useState<WeatherData | null>(null);
  const [forecast, setForecast] = useState<ForecastData | null>(null);
  const [aqi, setAqi] = useState<AQIData | null>(null);
  const [uv, setUv] = useState<number | null>(null);
  const [hotspot, setHotspot] = useState<{ name: string; aqi: number } | undefined>();
  const [aiInsight, setAiInsight] = useState<string>('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Auth State
  const [user, setUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('rx_user');
    return saved ? JSON.parse(saved) : null;
  });
  const [history, setHistory] = useState<string[]>(() => {
    const saved = localStorage.getItem('rx_history');
    return saved ? JSON.parse(saved) : [];
  });
  const [showHistory, setShowHistory] = useState(false);

  // Time state
  const [currentTime, setCurrentTime] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const getUVStatus = (val: number) => {
    if (val <= 2) return { label: "Low", color: "text-green-400" };
    if (val <= 5) return { label: "Mod", color: "text-yellow-400" };
    if (val <= 7) return { label: "High", color: "text-orange-400" };
    if (val <= 10) return { label: "Very High", color: "text-red-400" };
    return { label: "Extreme", color: "text-purple-500" };
  };

  const handleSearch = useCallback(async (query: string) => {
    if (!query) return;
    setLoading(true);
    setError(null);
    setShowHistory(false);
    try {
      const weatherData = await fetchWeatherByCity(query);
      const [forecastData, aqiData, uvValue] = await Promise.all([
        fetchForecast(weatherData.coord.lat, weatherData.coord.lon),
        fetchAQI(weatherData.coord.lat, weatherData.coord.lon),
        fetchUVIndex(weatherData.coord.lat, weatherData.coord.lon)
      ]);

      setWeather(weatherData);
      setForecast(forecastData);
      setAqi(aqiData);
      setUv(uvValue);

      // AI Insight - non blocking
      getWeatherInsight(weatherData, aqiData, uvValue).then(setAiInsight);

      // Save History
      if (user) {
        setHistory(prev => {
          const updated = [weatherData.name, ...prev.filter(i => i !== weatherData.name)].slice(0, 5);
          localStorage.setItem('rx_history', JSON.stringify(updated));
          return updated;
        });
      }
    } catch (err: any) {
      setError(err.message || "Failed to fetch weather data");
    } finally {
      setLoading(false);
    }
  }, [user]);

  const handleLocationSearch = useCallback(() => {
    if (!navigator.geolocation) return alert("Geolocation not supported");

    setLoading(true);
    navigator.geolocation.getCurrentPosition(async (pos) => {
      try {
        const weatherData = await fetchWeatherByCoords(pos.coords.latitude, pos.coords.longitude);
        const [forecastData, aqiData, uvValue] = await Promise.all([
          fetchForecast(weatherData.coord.lat, weatherData.coord.lon),
          fetchAQI(weatherData.coord.lat, weatherData.coord.lon),
          fetchUVIndex(weatherData.coord.lat, weatherData.coord.lon)
        ]);
        setWeather(weatherData);
        setForecast(forecastData);
        setAqi(aqiData);
        setUv(uvValue);
        getWeatherInsight(weatherData, aqiData, uvValue).then(setAiInsight);
      } catch (err: any) {
        setError(err.message);
      } finally {
        setLoading(false);
      }
    }, (err) => {
      setLoading(false);
      setError("Location permission denied");
    });
  }, []);

  useEffect(() => {
    handleSearch("Kathmandu"); // Default city set to Kathmandu
    getHotspotData().then(setHotspot);
  }, []);

  const toggleView = () => {
    const modes: ViewMode[] = ['auto', 'mobile', 'pc'];
    const next = modes[(modes.indexOf(viewMode) + 1) % 3];
    setViewMode(next);
  };

  const handleLogin = (newUser: User) => {
    setUser(newUser);
    localStorage.setItem('rx_user', JSON.stringify(newUser));
  };

  return (
    <div className={`min-h-screen p-4 flex items-center justify-center transition-all duration-500 ${viewMode === 'mobile' ? 'max-w-md mx-auto' : 'w-full'}`}>
      <Background />

      {/* Nav Buttons */}
      <div className="fixed top-6 left-6 flex gap-2 sm:gap-3 z-50">
        <button 
          onClick={() => setIsMenuOpen(!isMenuOpen)}
          className="w-10 h-10 sm:w-12 sm:h-12 glass rounded-full flex items-center justify-center hover:bg-orange-600 hover:scale-110 active:scale-90 transition-all duration-300 shadow-lg shadow-black/20"
        >
          <i className={`fas ${isMenuOpen ? 'fa-times' : 'fa-ellipsis-v'} text-sm sm:text-base transition-transform duration-300 ${isMenuOpen ? 'rotate-90' : ''}`} />
        </button>

        <button 
          onClick={() => user ? null : setIsLoginOpen(true)}
          className={`px-4 sm:px-6 h-10 sm:h-12 glass rounded-full flex items-center gap-2 font-bold text-xs sm:text-sm transition-all duration-300 shadow-lg shadow-black/20 ${user ? 'border-green-500/50 text-green-400' : 'hover:scale-105 active:scale-95 hover:bg-white/10'}`}
        >
          <i className={`fas ${user ? 'fa-user-check' : 'fa-user'} ${user ? 'animate-bounce' : ''}`} />
          {user ? user.nickname : 'Login'}
        </button>
      </div>

      <button 
        onClick={toggleView}
        className="fixed top-6 right-6 px-4 sm:px-6 h-10 sm:h-12 glass rounded-full flex items-center gap-2 font-bold text-[10px] sm:text-sm uppercase tracking-tighter hover:scale-105 active:scale-95 transition-all duration-300 z-50 shadow-lg shadow-black/20 hover:bg-white/10"
      >
        <i className="fas fa-magic transition-transform group-hover:rotate-45" />
        {viewMode}
      </button>

      {/* Menu Dropdown */}
      {isMenuOpen && (
        <div className="fixed top-20 left-6 w-48 sm:w-56 glass rounded-2xl p-2 z-50 animate-in fade-in slide-in-from-top-4 duration-300 shadow-2xl">
          <button 
            onClick={() => { setIsContactOpen(true); setIsMenuOpen(false); }}
            className="w-full text-left px-4 py-2 sm:py-3 rounded-xl hover:bg-white/10 flex items-center gap-3 transition-all duration-200 hover:translate-x-1 text-xs sm:text-sm"
          >
            <i className="fas fa-envelope opacity-50 text-orange-500" /> Contact Us
          </button>
          {user && (
             <button 
             onClick={() => { setUser(null); localStorage.removeItem('rx_user'); setIsMenuOpen(false); }}
             className="w-full text-left px-4 py-2 sm:py-3 rounded-xl hover:bg-red-500/20 text-red-400 flex items-center gap-3 transition-all duration-200 hover:translate-x-1 text-xs sm:text-sm"
           >
             <i className="fas fa-sign-out-alt opacity-50" /> Logout
           </button>
          )}
        </div>
      )}

      {/* Main Card */}
      <div className={`glass w-full max-w-2xl rounded-[32px] sm:rounded-[40px] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-700 ${viewMode === 'pc' ? 'scale-110' : ''}`}>
        {/* Header */}
        <div className="bg-black/20 p-4 sm:p-6 flex justify-between items-center border-b border-white/5">
          <div className="flex items-center gap-2 sm:gap-3 text-sm sm:text-lg font-black tracking-widest uppercase">
            <i className="fas fa-cloud-sun text-orange-500 animate-pulse" /> RX WEATHER
          </div>
          <div className="text-right">
            <div className="text-[8px] sm:text-[10px] font-bold opacity-60 uppercase tracking-widest">
              {currentTime.toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric' })}
            </div>
            <div className="text-sm sm:text-xl font-bold font-mono">
              {currentTime.toLocaleTimeString('en-US', { hour12: true, hour: '2-digit', minute: '2-digit' })}
            </div>
          </div>
        </div>

        {/* Search */}
        <div className="p-4 sm:p-8 pb-2 sm:pb-4 relative">
          <div className="flex gap-1.5 p-1 bg-white/5 border border-white/10 rounded-full focus-within:bg-black/40 focus-within:border-orange-500/50 transition-all duration-500 shadow-inner">
            <input 
              type="text" 
              placeholder="Search location..." 
              className="bg-transparent flex-1 px-3 sm:px-6 outline-none text-sm sm:text-lg placeholder:opacity-40"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              onFocus={() => setShowHistory(true)}
              onKeyDown={(e) => e.key === 'Enter' && handleSearch(searchQuery)}
            />
            {/* Optimized Search Buttons for Mobile */}
            <button 
              onClick={() => weather && handleSearch(weather.name)} 
              className={`w-9 h-9 sm:w-12 sm:h-12 rounded-full hover:bg-blue-500/20 hover:text-blue-400 flex items-center justify-center transition-all duration-300 active:scale-90 ${loading ? 'pointer-events-none opacity-40' : ''}`}
              title="Refresh current weather"
              disabled={loading || !weather}
            >
              <i className={`fas fa-sync-alt text-xs sm:text-base ${loading ? 'animate-spin' : ''}`} />
            </button>
            <button 
              onClick={handleLocationSearch} 
              className="w-9 h-9 sm:w-12 sm:h-12 rounded-full hover:bg-green-500/20 hover:text-green-400 flex items-center justify-center transition-all duration-300 active:scale-90"
              title="Use current location"
            >
              <i className="fas fa-location-arrow text-xs sm:text-base" />
            </button>
            <button 
              onClick={() => handleSearch(searchQuery)} 
              className="w-9 h-9 sm:w-12 sm:h-12 bg-orange-600 rounded-full flex items-center justify-center hover:bg-orange-500 hover:rotate-90 hover:scale-110 active:scale-90 transition-all duration-500 shadow-lg shadow-orange-500/20"
            >
              <i className="fas fa-search text-xs sm:text-base" />
            </button>
          </div>

          {/* History dropdown */}
          {showHistory && user && history.length > 0 && (
            <div className="absolute top-16 sm:top-24 left-6 right-6 sm:left-10 sm:right-10 glass rounded-2xl p-1 sm:p-2 z-40 border-white/20 animate-in fade-in slide-in-from-top-1 shadow-2xl">
              {history.map((h, i) => (
                <button 
                  key={i} 
                  onClick={() => { setSearchQuery(h); handleSearch(h); }}
                  className="w-full text-left px-3 py-2 sm:py-3 rounded-xl hover:bg-white/10 flex items-center justify-between group transition-all duration-200 hover:translate-x-1"
                >
                  <span className="flex items-center gap-2 sm:gap-3 text-xs sm:text-sm font-medium"><i className="fas fa-history opacity-30 text-[10px]" /> {h}</span>
                  <i className="fas fa-arrow-right text-[10px] opacity-0 group-hover:opacity-30 transition-all duration-300 group-hover:translate-x-1" />
                </button>
              ))}
            </div>
          )}
        </div>

        {/* Content Area */}
        <div className="px-4 sm:px-8 pb-4 sm:pb-8">
          {error && (
            <div className="bg-red-500/20 border-l-4 border-red-500 p-3 sm:p-4 rounded-xl mb-4 animate-in shake-in">
