import React, { useEffect, useRef, useState } from 'react';
import { OPENWEATHER_API_KEY } from '../constants';

interface MapDisplayProps {
  lat: number;
  lon: number;
  cityName: string;
}

type MapLayer = 'satellite' | 'streets' | 'terrain';

interface RadarFrame {
  time: number;
  path: string;
}

const MapDisplay: React.FC<MapDisplayProps> = ({ lat, lon, cityName }) => {
  const mapRef = useRef<any>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const [activeLayer, setActiveLayer] = useState<MapLayer>('satellite');
  const layersRef = useRef<Record<string, any>>({});

  // Radar Animation State
  const [radarFrames, setRadarFrames] = useState<RadarFrame[]>([]);
  const [activeFrameIndex, setActiveFrameIndex] = useState(-1);
  const [isPlaying, setIsPlaying] = useState(false);
  const radarLayersRef = useRef<any[]>([]);
  const animationIntervalRef = useRef<number | null>(null);

  const layerConfigs = {
    satellite: {
      url: 'https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}',
      attribution: 'Esri, DigitalGlobe, GeoEye, Earthstar Geographics'
    },
    streets: {
      url: 'https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png',
      attribution: '&copy; OpenStreetMap contributors &copy; CARTO'
    },
    terrain: {
      url: 'https://server.arcgisonline.com/ArcGIS/rest/services/World_Topo_Map/MapServer/tile/{z}/{y}/{x}',
      attribution: 'Esri, HERE, Garmin, Intermap'
    }
  };

  // 1. Initialize Map
  useEffect(() => {
    if (!containerRef.current) return;

    if (!mapRef.current) {
      // @ts-ignore
      mapRef.current = L.map(containerRef.current, { 
        zoomControl: false,
        attributionControl: false 
      }).setView([lat, lon], 10);

      updateBaseLayer('satellite');
      fetchRadarFrames();
    } else {
      mapRef.current.flyTo([lat, lon], 10);
    }

    return () => {
      if (animationIntervalRef.current) window.clearInterval(animationIntervalRef.current);
    };
  }, [lat, lon]);

  // 2. Fetch Radar Timestamps from RainViewer (Standard for Animation)
  const fetchRadarFrames = async () => {
    try {
      const response = await fetch('https://api.rainviewer.com/public/weather-maps.json');
      const data = await response.json();
      const frames: RadarFrame[] = data.radar.past.map((f: any) => ({
        time: f.time,
        path: f.path
      }));
      setRadarFrames(frames);
      setActiveFrameIndex(frames.length - 1); // Start with most recent
    } catch (error) {
      console.error("Failed to fetch radar frames:", error);
    }
  };

  // 3. Update Base Tile Layer
  const updateBaseLayer = (layerType: MapLayer) => {
    if (!mapRef.current) return;
    Object.values(layersRef.current).forEach(layer => mapRef.current.removeLayer(layer));

    // @ts-ignore
    const newLayer = L.tileLayer(layerConfigs[layerType].url, {
      maxZoom: 18,
      attribution: layerConfigs[layerType].attribution
    });

    newLayer.addTo(mapRef.current);
    layersRef.current[layerType] = newLayer;

    if (layerType === 'satellite') {
      // @ts-ignore
      const labels = L.tileLayer('https://{s}.basemaps.cartocdn.com/rastertiles/voyager_only_labels/{z}/{x}/{y}{r}.png', {
        subdomains: 'abcd',
        maxZoom: 18,
        zIndex: 50
      });
      labels.addTo(mapRef.current);
      layersRef.current['labels'] = labels;
    }
  };

  useEffect(() => {
    updateBaseLayer(activeLayer);
  }, [activeLayer]);

  // 4. Manage Radar Layers Animation
  useEffect(() => {
    if (!mapRef.current || radarFrames.length === 0) return;

    // Clear existing radar layers
    radarLayersRef.current.forEach(layer => mapRef.current.removeLayer(layer));
    radarLayersRef.current = [];

    // Pre-load all frames but keep them hidden (opacity 0)
    radarFrames.forEach((frame, idx) => {
      // @ts-ignore
      const layer = L.tileLayer(`https://tilecache.rainviewer.com${frame.path}/256/{z}/{x}/{y}/2/1_1.png`, {
        opacity: 0,
        zIndex: 100 + idx
      }).addTo(mapRef.current);
      radarLayersRef.current[idx] = layer;
    });

    // Initial show
    if (activeFrameIndex !== -1 && radarLayersRef.current[activeFrameIndex]) {
      radarLayersRef.current[activeFrameIndex].setOpacity(0.6);
    }
  }, [radarFrames]);

  // 5. Handle Animation Interval
  useEffect(() => {
    if (isPlaying) {
      animationIntervalRef.current = window.setInterval(() => {
        setActiveFrameIndex((prev) => (prev + 1) % radarFrames.length);
      }, 600);
    } else {
      if (animationIntervalRef.current) window.clearInterval(animationIntervalRef.current);
    }
    return () => {
      if (animationIntervalRef.current) window.clearInterval(animationIntervalRef.current);
    };
  }, [isPlaying, radarFrames.length]);

  // 6. Update Visible Frame
  useEffect(() => {
    radarLayersRef.current.forEach((layer, idx) => {
      if (layer) layer.setOpacity(idx === activeFrameIndex ? 0.6 : 0);
    });
  }, [activeFrameIndex]);

  const formatTime = (ts: number) => {
    return new Date(ts * 1000).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  return (
    <div className="relative w-full h-full rounded-[24px] sm:rounded-[32px] overflow-hidden border border-white/20 mt-4 sm:mt-6 group bg-slate-800 shadow-2xl transition-all duration-500">
      <div ref={containerRef} className="w-full h-full" />

      {/* City Label */}
      <div className="absolute top-3 left-3 sm:top-4 left-4 z-[400] bg-black/60 backdrop-blur-md px-3 py-1 sm:px-4 sm:py-2 rounded-lg sm:rounded-xl text-[8px] sm:text-[10px] font-black pointer-events-none uppercase tracking-[0.1em] sm:tracking-[0.2em] flex items-center gap-1.5 sm:gap-2 border border-white/10 shadow-lg transition-transform group-hover:translate-x-1">
        <span className="w-1.5 h-1.5 sm:w-2 sm:h-2 rounded-full bg-orange-500 animate-pulse shadow-[0_0_8px_rgba(249,115,22,0.5)]" />
        {cityName} RADAR
      </div>

      {/* Layer Switcher */}
      <div className="absolute top-3 right-3 sm:top-4 right-4 z-[400] flex flex-col gap-1.5 sm:gap-2">
        {(['satellite', 'streets', 'terrain'] as MapLayer[]).map((layer) => (
          <button
            key={layer}
            onClick={() => setActiveLayer(layer)}
            className={`w-9 h-9 sm:w-11 sm:h-11 rounded-lg sm:rounded-xl flex items-center justify-center transition-all duration-300 border backdrop-blur-md shadow-xl active:scale-90
              ${activeLayer === layer 
                ? 'bg-orange-600 border-orange-400 text-white scale-110 shadow-orange-500/30' 
                : 'bg-black/40 border-white/10 text-white/60 hover:bg-black/60 hover:text-white hover:scale-105'
              }`}
            title={layer.charAt(0).toUpperCase() + layer.slice(1)}
          >
            <i className={`fas ${
              layer === 'satellite' ? 'fa-globe' : 
              layer === 'streets' ? 'fa-road' : 'fa-mountain'
            } text-xs sm:text-base transition-transform duration-300`} />
          </button>
        ))}
      </div>

      {/* Radar Animation Player Bar */}
      {radarFrames.length > 0 && (
        <div className="absolute bottom-3 left-3 right-3 sm:bottom-4 left-4 right-4 z-[400] glass border-white/10 rounded-xl sm:rounded-2xl p-2.5 sm:p-4 flex items-center gap-3 sm:gap-5 animate-in slide-in-from-bottom-6 duration-700 shadow-2xl">
          <button 
            onClick={() => setIsPlaying(!isPlaying)}
            className="w-10 h-10 sm:w-12 sm:h-12 bg-orange-600 hover:bg-orange-500 rounded-lg sm:rounded-xl flex items-center justify-center transition-all duration-300 shrink-0 shadow-lg shadow-orange-500/20 active:scale-90 hover:scale-105"
          >
            <i className={`fas ${isPlaying ? 'fa-pause' : 'fa-play'} text-xs sm:text-sm transition-transform duration-300 ${isPlaying ? 'scale-110' : ''}`} />
          </button>

          <div className="flex-1 flex flex-col gap-1.5 sm:gap-2">
            <div className="flex justify-between items-center text-[7px] sm:text-[10px] font-black tracking-widest uppercase opacity-80">
              <span className="text-orange-500 flex items-center gap-1 sm:gap-2">
                {isPlaying && <span className="w-1 h-1 sm:w-1.5 sm:h-1.5 bg-orange-500 rounded-full animate-ping" />}
                Loop
              </span>
              <span className="bg-white/10 px-1.5 py-0.5 rounded-md">{formatTime(radarFrames[activeFrameIndex]?.time)}</span>
            </div>

            <div className="relative h-1.5 sm:h-2 bg-white/5 rounded-full overflow-hidden shadow-inner group/slider">
              <div 
                className="absolute top-0 left-0 h-full bg-orange-500 transition-all duration-300 shadow-[0_0_8px_rgba(249,115,22,0.5)]"
                style={{ width: `${((activeFrameIndex + 1) / radarFrames.length) * 100}%` }}
              />
              <input 
                type="range"
                min="0"
                max={radarFrames.length - 1}
                value={activeFrameIndex}
                onChange={(e) => {
                  setIsPlaying(false);
                  setActiveFrameIndex(parseInt(e.target.value));
                }}
                className="absolute inset-0 w-full opacity-0 cursor-pointer z-10"
              />
            </div>
          </div>

          <div className="hidden sm:flex flex-col items-end text-[8px] sm:text-[10px] font-black opacity-30 uppercase tracking-[0.1em] sm:tracking-[0.2em] shrink-0">
            <span>Past 2h</span>
            <span>{radarFrames.length} F</span>
          </div>
        </div>
      )}
    </div>
  );
};

export default MapDisplay;

import React, { useState, useEffect, useCallback } from 'react';
import Background from './components/Background';
import MapDisplay from './components/MapDisplay';
import LoginModal from './components/Auth';
import { ForecastModal, AQIModal } from './components/ForecastModals';
import { 
  fetchWeatherByCity, 
  fetchWeatherByCoords, 
  fetchForecast, 
  fetchAQI, 
  fetchUVIndex,
  getHotspotData 
} from './services/weatherService';
import { getWeatherInsight } from './services/geminiService';
import { 
  WeatherData, 
  ForecastData, 
  AQIData, 
  User, 
  ViewMode 
} from './types';
import { COLORS } from './constants';

const App: React.FC = () => {
  // UI State
  const [viewMode, setViewMode] = useState<ViewMode>('auto');
  const [isLoginOpen, setIsLoginOpen] = useState(false);
  const [isHourlyOpen, setIsHourlyOpen] = useState(false);
  const [isDailyOpen, setIsDailyOpen] = useState(false);
  const [isAQIOpen, setIsAQIOpen] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isContactOpen, setIsContactOpen] = useState(false);

  // Data State
  const [searchQuery, setSearchQuery] = useState('');
  const [weather, setWeather] = useState<WeatherData | null>(null);
  const [forecast, setForecast] = useState<ForecastData | null>(null);
  const [aqi, setAqi] = useState<AQIData | null>(null);
  const [uv, setUv] = useState<number | null>(null);
  const [hotspot, setHotspot] = useState<{ name: string; aqi: number } | undefined>();
  const [aiInsight, setAiInsight] = useState<string>('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Auth State
  const [user, setUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('rx_user');
    return saved ? JSON.parse(saved) : null;
  });
  const [history, setHistory] = useState<string[]>(() => {
    const saved = localStorage.getItem('rx_history');
    return saved ? JSON.parse(saved) : [];
  });
  const [showHistory, setShowHistory] = useState(false);

  // Time state
  const [currentTime, setCurrentTime] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const getUVStatus = (val: number) => {
    if (val <= 2) return { label: "Low", color: "text-green-400" };
    if (val <= 5) return { label: "Mod", color: "text-yellow-400" };
    if (val <= 7) return { label: "High", color: "text-orange-400" };
    if (val <= 10) return { label: "Very High", color: "text-red-400" };
    return { label: "Extreme", color: "text-purple-500" };
  };

  const handleSearch = useCallback(async (query: string) => {
    if (!query) return;
    setLoading(true);
    setError(null);
    setShowHistory(false);
    try {
      const weatherData = await fetchWeatherByCity(query);
      const [forecastData, aqiData, uvValue] = await Promise.all([
        fetchForecast(weatherData.coord.lat, weatherData.coord.lon),
        fetchAQI(weatherData.coord.lat, weatherData.coord.lon),
        fetchUVIndex(weatherData.coord.lat, weatherData.coord.lon)
      ]);

      setWeather(weatherData);
      setForecast(forecastData);
      setAqi(aqiData);
      setUv(uvValue);

      getWeatherInsight(weatherData, aqiData, uvValue).then(setAiInsight);

      if (user) {
        setHistory(prev => {
          const updated = [weatherData.name, ...prev.filter(i => i !== weatherData.name)].slice(0, 5);
          localStorage.setItem('rx_history', JSON.stringify(updated));
          return updated;
        });
      }
    } catch (err: any) {
      setError(err.message || "Failed to fetch weather data");
    } finally {
      setLoading(false);
    }
  }, [user]);

  const handleLocationSearch = useCallback(() => {
    if (!navigator.geolocation) return alert("Geolocation not supported");

    setLoading(true);
    navigator.geolocation.getCurrentPosition(async (pos) => {
      try {
        const weatherData = await fetchWeatherByCoords(pos.coords.latitude, pos.coords.longitude);
        const [forecastData, aqiData, uvValue] = await Promise.all([
          fetchForecast(weatherData.coord.lat, weatherData.coord.lon),
          fetchAQI(weatherData.coord.lat, weatherData.coord.lon),
          fetchUVIndex(weatherData.coord.lat, weatherData.coord.lon)
        ]);
        setWeather(weatherData);
        setForecast(forecastData);
        setAqi(aqiData);
        setUv(uvValue);
        getWeatherInsight(weatherData, aqiData, uvValue).then(setAiInsight);
      } catch (err: any) {
        setError(err.message);
      } finally {
        setLoading(false);
      }
    }, (err) => {
      setLoading(false);
      setError("Location permission denied");
    });
  }, []);

  useEffect(() => {
    handleSearch("Kathmandu");
    getHotspotData().then(setHotspot);
  }, []);

  const toggleView = () => {
    const modes: ViewMode[] = ['auto', 'mobile', 'pc'];
    const next = modes[(modes.indexOf(viewMode) + 1) % 3];
    setViewMode(next);
  };

  const handleLogin = (newUser: User) => {
    setUser(newUser);
    localStorage.setItem('rx_user', JSON.stringify(newUser));
  };

  return (
    <div className={`min-h-screen py-10 px-4 flex flex-col items-center justify-start transition-all duration-500 ${viewMode === 'mobile' ? 'max-w-md mx-auto' : 'w-full'}`}>
      <Background />

      {/* Top Navigation Bar - Grouped Controls Above Card */}
      <div className="w-full max-w-2xl flex items-center justify-between mb-4 z-50">
        <div className="flex gap-2">
          {/* Menu Trigger */}
          <div className="relative">
            <button 
              onClick={() => setIsMenuOpen(!isMenuOpen)}
              className="w-10 h-10 sm:w-11 sm:h-11 glass rounded-2xl flex items-center justify-center hover:bg-orange-600 hover:scale-110 active:scale-95 transition-all duration-300 shadow-xl"
            >
              <i className={`fas ${isMenuOpen ? 'fa-times' : 'fa-ellipsis-v'} text-xs sm:text-sm transition-transform ${isMenuOpen ? 'rotate-90' : ''}`} />
            </button>

            {isMenuOpen && (
              <div className="absolute top-full left-0 mt-2 w-48 glass rounded-2xl p-2 animate-in fade-in slide-in-from-top-4 duration-300 shadow-2xl border border-white/10">
                <button 
                  onClick={() => { setIsContactOpen(true); setIsMenuOpen(false); }}
                  className="w-full text-left px-4 py-2 rounded-xl hover:bg-white/10 flex items-center gap-3 text-xs font-bold transition-all"
                >
                  <i className="fas fa-envelope text-orange-500" /> Contact Us
                </button>
                {user && (
                   <button 
                   onClick={() => { setUser(null); localStorage.removeItem('rx_user'); setIsMenuOpen(false); }}
                   className="w-full text-left px-4 py-2 rounded-xl hover:bg-red-500/20 text-red-400 flex items-center gap-3 text-xs font-bold transition-all"
                 >
                   <i className="fas fa-sign-out-alt" /> Logout
                 </button>
                )}
              </div>
            )}
          </div>

          {/* Login/User Button */}
          <button 
            onClick={() => user ? null : setIsLoginOpen(true)}
            className={`px-3 sm:px-5 h-10 sm:h-11 glass rounded-2xl flex items-center gap-2 font-black text-[10px] sm:text-xs uppercase tracking-widest transition-all duration-300 shadow-xl ${user ? 'border-green-500/50 text-green-400' : 'hover:scale-105 active:scale-95 hover:bg-white/10'}`}
          >
            <i className={`fas ${user ? 'fa-user-check' : 'fa-user'} ${user ? 'animate-bounce' : ''}`} />
            {user ? user.nickname : 'Login'}
          </button>
        </div>

        {/* View Switcher */}
        <button 
          onClick={toggleView}
          className="h-10 sm:h-11 px-3 sm:px-5 glass rounded-2xl flex items-center gap-2 font-black text-[10px] sm:text-xs uppercase tracking-widest hover:scale-105 active:scale-95 transition-all duration-300 shadow-xl hover:bg-white/10"
        >
          <i className="fas fa-magic text-cyan-400" />
          <span className="hidden sm:inline">{viewMode}</span>
        </button>
      </div>

      {/* Main Glass Card */}
      <div className={`glass w-full max-w-2xl rounded-[32px] sm:rounded-[40px] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-700 ${viewMode === 'pc' ? 'scale-110 mt-8' : ''}`}>
        {/* Card Header */}
        <div className="bg-black/20 p-4 sm:p-6 flex justify-between items-center border-b border-white/5">
          <div className="flex items-center gap-2 sm:gap-3 text-sm sm:text-lg font-black tracking-widest uppercase">
            <i className="fas fa-cloud-sun text-orange-500 animate-pulse" /> RX WEATHER
          </div>
          <div className="text-right">
            <div className="text-[8px] sm:text-[10px] font-bold opacity-60 uppercase tracking-widest">
              {currentTime.toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric' })}
            </div>
            <div className="text-sm sm:text-xl font-bold font-mono">
              {currentTime.toLocaleTimeString('en-US', { hour12: true, hour: '2-digit', minute: '2-digit' })}
            </div>
          </div>
        </div>

        {/* Search Bar Group */}
        <div className="p-4 sm:p-8 pb-2 sm:pb-4 relative">
          <div className="flex gap-1.5 p-1 bg-white/5 border border-white/10 rounded-full focus-within:bg-black/40 focus-within:border-orange-500/50 transition-all duration-500 shadow-inner">
            <input 
              type="text" 
              placeholder="Search location..." 
              className="bg-transparent flex-1 px-3 sm:px-6 outline-none text-sm sm:text-lg placeholder:opacity-40"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              onFocus={() => setShowHistory(true)}
              onKeyDown={(e) => e.key === 'Enter' && handleSearch(searchQuery)}
            />
            <button 
              onClick={() => weather && handleSearch(weather.name)} 
              className={`w-9 h-9 sm:w-11 sm:h-11 rounded-full hover:bg-blue-500/20 hover:text-blue-400 flex items-center justify-center transition-all duration-300 active:scale-90 ${loading ? 'pointer-events-none opacity-40' : ''}`}
              title="Refresh"
              disabled={loading || !weather}
            >
              <i className={`fas fa-sync-alt text-xs sm:text-base ${loading ? 'animate-spin' : ''}`} />
            </button>
            <button 
              onClick={handleLocationSearch} 
              className="w-9 h-9 sm:w-11 sm:h-11 rounded-full hover:bg-green-500/20 hover:text-green-400 flex items-center justify-center transition-all duration-300 active:scale-90"
              title="Location"
            >
              <i className="fas fa-location-arrow text-xs sm:text-base" />
            </button>
            <button 
              onClick={() => handleSearch(searchQuery)} 
              className="w-9 h-9 sm:w-11 sm:h-11 bg-orange-600 rounded-full flex items-center justify-center hover:bg-orange-500 hover:rotate-90 hover:scale-110 active:scale-90 transition-all duration-500 shadow-lg shadow-orange-500/20"
            >
              <i className="fas fa-search text-xs sm:text-base" />
            </button>
          </div>

          {/* Search History */}
          {showHistory && user && history.length > 0 && (
            <div className="absolute top-16 sm:top-24 left-6 right-6 sm:left-10 sm:right-10 glass rounded-2xl p-1 sm:p-2 z-40 border-white/20 animate-in fade-in slide-in-from-top-1 shadow-2xl">
              {history.map((h, i) => (
                <button 
                  key={i} 
                  onClick={() => { setSearchQuery(h); handleSearch(h); }}
                  className="w-full text-left px-3 py-2 sm:py-3 rounded-xl hover:bg-white/10 flex items-center justify-between group transition-all duration-200 hover:translate-x-1"
                >
                  <span className="flex items-center gap-2 sm:gap-3 text-xs sm:text-sm font-medium"><i className="fas fa-history opacity-30 text-[10px]" /> {h}</span>
                  <i className="fas fa-arrow-right text-[10px] opacity-0 group-hover:opacity-30 transition-all duration-300 group-hover:translate-x-1" />
                </button>
              ))}
            </div>
          )}
        </div>

        {/* Content Area */}
        <div className="px-4 sm:px-8 pb-4 sm:pb-8">
          {error && (
            <div className="bg-red-500/20 border-l-4 border-red-500 p-3 sm:p-4 rounded-xl mb-4 animate-in shake-in">
              <span className="font-bold uppercase text-[8px] sm:text-[10px] block mb-1 text-red-400 tracking-widest">Error detected</span>
              <span className="text-xs font-medium">{error}</span>
            </div>
          )}

          {weather && !loading ? (
            <div className="animate-in fade-in slide-in-from-bottom-4 duration-700">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4 sm:gap-8 items-center border-b border-white/10 pb-4 sm:pb-8">
                {/* Weather Overview */}
                <div className="flex flex-col">
                  <div className="flex items-center gap-2 sm:gap-4">
                    <img src={`https://openweathermap.org/img/wn/${weather.weather[0].icon}@4x.png`} className="w-20 h-20 sm:w-24 sm:h-24 drop-shadow-2xl animate-[float_4s_ease-in-out_infinite]" alt="icon" />
                    <div>
                      <div className="text-5xl sm:text-7xl font-bold tracking-tighter">{Math.round(weather.main.temp)}<span className="text-2xl sm:text-3xl font-light align-top mt-1 sm:mt-2 inline-block">°C</span></div>
                      <div className="text-[10px] sm:text-sm font-medium opacity-60 uppercase tracking-widest">Feels like {Math.round(weather.main.feels_like)}°</div>
                    </div>
                  </div>
                  <div className="text-lg sm:text-2xl font-black mt-2 sm:mt-4 flex items-center gap-2 group cursor-default tracking-tight">
                    <i className="fas fa-map-marker-alt text-orange-500 transition-transform group-hover:scale-125" />
                    {weather.name}, {weather.sys.country}
                  </div>
                </div>

                {/* Detailed Metrics */}
                <div className="grid grid-cols-2 md:grid-cols-1 gap-2 sm:space-y-3">
                  {[
                    { label: "Today's Low", val: `${Math.round(weather.main.temp_min)}°C` },
                    { label: "Wind Speed", val: `${Math.round(weather.wind.speed * 3.6)} km/h` },
                    { label: "Humidity", val: `${weather.main.humidity}%` },
                    { label: "Pressure", val: `${weather.main.pressure} mb` },
                    { label: "UV Index", val: uv !== null ? (
                      <span className="flex items-center gap-1 sm:gap-2">
                        {Math.round(uv)} 
                        <span className={`text-[7px] sm:text-[10px] font-black uppercase px-1.5 sm:px-2 py-0.5 rounded-full bg-white/10 ${getUVStatus(uv).color} animate-pulse`}>
                          {getUVStatus(uv).label}
                        </span>
                      </span>
                    ) : '--' },
                  ].map((d, i) => (
                    <div key={i} className="flex justify-between items-center py-1.5 sm:py-2 border-b border-white/5 last:border-0 hover:bg-white/5 transition-colors px-2 -mx-2 rounded-lg">
                      <span className="text-[9px] sm:text-xs opacity-50 font-black uppercase tracking-widest">{d.label}</span>
                      <span className="font-bold flex items-center text-[10px] sm:text-xs">{d.val}</span>
                    </div>
                  ))}
                </div>
              </div>

              {/* Gemini AI Insight */}
              {aiInsight && (
                <div className="mt-4 sm:mt-6 p-4 sm:p-5 bg-gradient-to-r from-blue-600/20 to-purple-600/20 border border-white/10 rounded-2xl flex items-start gap-3 sm:gap-4 group transition-all duration-300 hover:scale-[1.01] hover:shadow-xl hover:shadow-blue-500/5">
                  <div className="w-8 h-8 sm:w-10 sm:h-10 bg-white/10 rounded-xl flex items-center justify-center shrink-0 group-hover:bg-blue-600 transition-colors">
                    <i className="fas fa-robot text-blue-400 group-hover:text-white transition-colors text-xs sm:text-base" />
                  </div>
                  <div className="text-[10px] sm:text-sm italic opacity-90 leading-relaxed font-medium">
                    <span className="font-black text-blue-300 not-italic block mb-0.5 sm:mb-1 text-[8px] sm:text-[10px] tracking-widest uppercase">Atmospheric Insight</span>
                    "{aiInsight}"
                  </div>
                </div>
              )}

              {/* Action Buttons */}
              <div className="grid grid-cols-3 gap-2 sm:gap-3 mt-4 sm:mt-6">
                <button onClick={() => setIsHourlyOpen(true)} className="glass py-2.5 sm:py-3.5 rounded-xl sm:rounded-2xl text-[8px] sm:text-[10px] font-black uppercase hover:bg-orange-600 hover:scale-105 active:scale-95 transition-all duration-300 shadow-lg tracking-widest">Hourly</button>
                <button onClick={() => setIsDailyOpen(true)} className="glass py-2.5 sm:py-3.5 rounded-xl sm:rounded-2xl text-[8px] sm:text-[10px] font-black uppercase hover:bg-orange-600 hover:scale-105 active:scale-95 transition-all duration-300 shadow-lg tracking-widest">Daily</button>
                <button onClick={() => setIsAQIOpen(true)} className="glass py-2.5 sm:py-3.5 rounded-xl sm:rounded-2xl text-[8px] sm:text-[10px] font-black uppercase hover:bg-orange-600 hover:scale-105 active:scale-95 transition-all duration-300 shadow-lg tracking-widest">AQI Detail</button>
              </div>

              <div className="h-60 sm:h-80">
                <MapDisplay lat={weather.coord.lat} lon={weather.coord.lon} cityName={weather.name} />
              </div>
            </div>
          ) : (
            <div className="py-16 sm:py-24 flex flex-col items-center gap-4 sm:gap-6">
              <div className="relative">
                <div className="w-12 h-12 sm:w-16 sm:h-16 border-4 border-white/10 border-t-orange-500 rounded-full animate-spin" />
                <div className="absolute inset-0 flex items-center justify-center">
                  <i className="fas fa-satellite-dish text-orange-500 animate-pulse text-[10px] sm:text-xs" />
                </div>
              </div>
              <p className="opacity-50 text-[9px] sm:text-xs font-black uppercase tracking-[0.3em] animate-pulse">Syncing satellite link...</p>
            </div>
          )}
        </div>

        {/* Card Footer */}
        <div className="bg-black/30 p-6 sm:p-8 text-center space-y-1 sm:space-y-2 border-t border-white/5">
          <div className="text-[10px] sm:text-sm opacity-80 font-medium">Powered by <span className="font-black text-orange-500 hover:text-orange-400 cursor-help transition-colors">RX ENTERTAINMENT</span></div>
          <div className="text-[8px] sm:text-[10px] opacity-30 uppercase tracking-[0.2em] sm:tracking-[0.3em] font-bold">&copy; 2026 RX Weather. Engineered by Aman.</div>
          <div className="text-[10px] sm:text-xs font-black text-cyan-400 animate-pulse tracking-[0.3em] sm:tracking-[0.4em] pt-2 sm:pt-4">MADE WITH LOVE BY AMAN</div>
        </div>
      </div>

      {/* Social Shortcut */}
      <a 
        href="https://www.instagram.com/aman_devv/" 
        target="_blank" 
        rel="noreferrer"
        className="fixed bottom-6 right-6 w-11 h-11 sm:w-14 sm:h-14 glass rounded-full flex items-center justify-center text-xl sm:text-2xl group transition-all duration-500 hover:scale-125 hover:rotate-6 active:scale-90 shadow-2xl"
      >
        <i className="fab fa-instagram bg-gradient-to-tr from-[#f09433] via-[#dc2743] to-[#bc1888] bg-clip-text text-transparent" />
      </a>

      {/* Modals */}
      <LoginModal 
        isOpen={isLoginOpen} 
        onClose={() => setIsLoginOpen(false)} 
        onLogin={handleLogin} 
      />

      {forecast && (
        <>
          <ForecastModal 
            isOpen={isHourlyOpen} 
            onClose={() => setIsHourlyOpen(false)} 
            items={forecast.list.slice(0, 8)} 
            title="Next 24 Hours"
            type="hourly"
          />
          <ForecastModal 
            isOpen={isDailyOpen} 
            onClose={() => setIsDailyOpen(false)} 
            items={forecast.list.filter((_, i) => i % 8 === 0)} 
            title="5-Day Outlook"
            type="daily"
          />
        </>
      )}

      {aqi && (
        <AQIModal 
          isOpen={isAQIOpen} 
          onClose={() => setIsAQIOpen(false)} 
          aqiData={aqi} 
          hotspot={hotspot}
        />
      )}

      {/* Contact Overlay */}
      {isContactOpen && (
        <div className="fixed inset-0 z-[200] flex animate-in slide-in-from-left duration-700">
          <div className="w-64 sm:w-80 h-full bg-gradient-to-br from-indigo-900 to-purple-950 p-8 sm:p-12 flex flex-col justify-center relative shadow-[50px_0_100px_rgba(0,0,0,0.5)] border-r border-white/10">
            <button 
              onClick={() => setIsContactOpen(false)} 
              className="absolute top-6 sm:top-8 right-6 sm:right-8 text-2xl sm:text-3xl opacity-40 hover:opacity-100 transition-all duration-300"
            >
              &times;
            </button>
            <h2 className="text-3xl sm:text-4xl font-black mb-2 tracking-tighter">Get In Touch</h2>
            <p className="text-[10px] sm:text-xs opacity-50 mb-8 font-bold uppercase tracking-widest">Support & Inquiries</p>
            <div className="space-y-3">
              <div className="bg-black/30 p-4 rounded-2xl border border-white/5 font-mono text-[10px] sm:text-xs break-all">
                sdfre3511@gmail.com
              </div>
              <button 
                onClick={() => { navigator.clipboard.writeText("sdfre3511@gmail.com"); alert("Email copied!"); }}
                className="w-full bg-white text-indigo-950 py-3 rounded-2xl font-black uppercase text-[10px] sm:text-xs tracking-widest hover:scale-105 active:scale-95 transition-all shadow-xl"
              >
                Copy Email
              </button>
            </div>
          </div>
          <div className="flex-1 bg-black/40 backdrop-blur-md" onClick={() => setIsContactOpen(false)} />
        </div>
      )}

      <style>{`
        @keyframes float {
          0%, 100% { transform: translateY(0) rotate(0); }
          50% { transform: translateY(-10px) rotate(2deg); }
        }
      `}</style>
    </div>
  );
};

export default App;

export interface WeatherData {
  name: string;
  coord: { lat: number; lon: number };
  main: {
    temp: number;
    feels_like: number;
    temp_min: number;
    temp_max: number;
    pressure: number;
    humidity: number;
  };
  wind: { speed: number; gust?: number };
  weather: Array<{ description: string; icon: string; main: string }>;
  sys: { country: string; sunrise: number; sunset: number };
  timezone: number;
}

export interface ForecastItem {
  dt: number;
  main: { temp: number; humidity: number };
  weather: Array<{ description: string; icon: string }>;
  wind: { speed: number };
  pop: number;
}

export interface ForecastData {
  list: ForecastItem[];
}

export interface AQIData {
  aqi: number;
  components: {
    pm2_5: number;
    pm10: number;
    no2: number;
    o3: number;
    so2: number;
  };
}

export interface User {
  nickname: string;
  email: string;
}

export type ViewMode = 'auto' | 'mobile' | 'pc';

export interface UVData {
  value: number;
}

import React, { useState, useEffect, useCallback } from 'react';
import Background from './components/Background';
import MapDisplay from './components/MapDisplay';
import LoginModal from './components/Auth';
import { ForecastModal, AQIModal } from './components/ForecastModals';
import { 
  fetchWeatherByCity, 
  fetchWeatherByCoords, 
  fetchForecast, 
  fetchAQI, 
  fetchUVIndex,
  getHotspotData 
} from './services/weatherService';
import { getWeatherInsight } from './services/geminiService';
import { 
  WeatherData, 
  ForecastData, 
  AQIData, 
  User, 
  ViewMode 
} from './types';
import { COLORS } from './constants';

const App: React.FC = () => {
  // UI State
  const [viewMode, setViewMode] = useState<ViewMode>('auto');
  const [isLoginOpen, setIsLoginOpen] = useState(false);
  const [isHourlyOpen, setIsHourlyOpen] = useState(false);
  const [isDailyOpen, setIsDailyOpen] = useState(false);
  const [isAQIOpen, setIsAQIOpen] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isContactOpen, setIsContactOpen] = useState(false);

  // Data State
  const [searchQuery, setSearchQuery] = useState('');
  const [weather, setWeather] = useState<WeatherData | null>(null);
  const [forecast, setForecast] = useState<ForecastData | null>(null);
  const [aqi, setAqi] = useState<AQIData | null>(null);
  const [uv, setUv] = useState<number | null>(null);
  const [hotspot, setHotspot] = useState<{ name: string; aqi: number } | undefined>();
  const [aiInsight, setAiInsight] = useState<string>('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Auth State
  const [user, setUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('rx_user');
    return saved ? JSON.parse(saved) : null;
  });
  const [history, setHistory] = useState<string[]>(() => {
    const saved = localStorage.getItem('rx_history');
    return saved ? JSON.parse(saved) : [];
  });
  const [showHistory, setShowHistory] = useState(false);

  // Time state
  const [currentTime, setCurrentTime] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const formatSunTime = (timestamp: number, timezoneOffset: number) => {
    // OpenWeatherMap returns UTC timestamp in seconds. Timezone is offset in seconds from UTC.
    const date = new Date((timestamp + timezoneOffset) * 1000);
    return date.getUTCHours().toString().padStart(2, '0') + ":" + 
           date.getUTCMinutes().toString().padStart(2, '0');
  };

  const getUVStatus = (val: number) => {
    if (val <= 2) return { label: "Low", color: "text-green-400" };
    if (val <= 5) return { label: "Mod", color: "text-yellow-400" };
    if (val <= 7) return { label: "High", color: "text-orange-400" };
    if (val <= 10) return { label: "Very High", color: "text-red-400" };
    return { label: "Extreme", color: "text-purple-500" };
  };

  const handleSearch = useCallback(async (query: string) => {
    if (!query) return;
    setLoading(true);
    setError(null);
    setShowHistory(false);
    try {
      const weatherData = await fetchWeatherByCity(query);
      const [forecastData, aqiData, uvValue] = await Promise.all([
        fetchForecast(weatherData.coord.lat, weatherData.coord.lon),
        fetchAQI(weatherData.coord.lat, weatherData.coord.lon),
        fetchUVIndex(weatherData.coord.lat, weatherData.coord.lon)
      ]);

      setWeather(weatherData);
      setForecast(forecastData);
      setAqi(aqiData);
      setUv(uvValue);

      getWeatherInsight(weatherData, aqiData, uvValue).then(setAiInsight);

      if (user) {
        setHistory(prev => {
          const updated = [weatherData.name, ...prev.filter(i => i !== weatherData.name)].slice(0, 5);
          localStorage.setItem('rx_history', JSON.stringify(updated));
          return updated;
        });
      }
    } catch (err: any) {
      setError(err.message || "Failed to fetch weather data");
    } finally {
      setLoading(false);
    }
  }, [user]);

  const handleLocationSearch = useCallback(() => {
    if (!navigator.geolocation) return alert("Geolocation not supported");

    setLoading(true);
    navigator.geolocation.getCurrentPosition(async (pos) => {
      try {
        const weatherData = await fetchWeatherByCoords(pos.coords.latitude, pos.coords.longitude);
        const [forecastData, aqiData, uvValue] = await Promise.all([
          fetchForecast(weatherData.coord.lat, weatherData.coord.lon),
          fetchAQI(weatherData.coord.lat, weatherData.coord.lon),
          fetchUVIndex(weatherData.coord.lat, weatherData.coord.lon)
        ]);
        setWeather(weatherData);
        setForecast(forecastData);
        setAqi(aqiData);
        setUv(uvValue);
        getWeatherInsight(weatherData, aqiData, uvValue).then(setAiInsight);
      } catch (err: any) {
        setError(err.message);
      } finally {
        setLoading(false);
      }
    }, (err) => {
      setLoading(false);
      setError("Location permission denied");
    });
  }, []);

  useEffect(() => {
    handleSearch("Kathmandu");
    getHotspotData().then(setHotspot);
  }, []);

  const toggleView = () => {
    const modes: ViewMode[] = ['auto', 'mobile', 'pc'];
    const next = modes[(modes.indexOf(viewMode) + 1) % 3];
    setViewMode(next);
  };

  const handleLogin = (newUser: User) => {
    setUser(newUser);
    localStorage.setItem('rx_user', JSON.stringify(newUser));
  };

  return (
    <div className={`min-h-screen py-10 px-4 flex flex-col items-center justify-start transition-all duration-500 ${viewMode === 'mobile' ? 'max-w-md mx-auto' : 'w-full'}`}>
      <Background />

      {/* Top Navigation Bar - Grouped Controls Above Card */}
      <div className="w-full max-w-2xl flex items-center justify-between mb-4 z-50">
        <div className="flex gap-2">
          {/* Menu Trigger */}
          <div className="relative">
            <button 
              onClick={() => setIsMenuOpen(!isMenuOpen)}
              className="w-10 h-10 sm:w-11 sm:h-11 glass rounded-2xl flex items-center justify-center hover:bg-orange-600 hover:scale-110 active:scale-95 transition-all duration-300 shadow-xl"
            >
              <i className={`fas ${isMenuOpen ? 'fa-times' : 'fa-ellipsis-v'} text-xs sm:text-sm transition-transform ${isMenuOpen ? 'rotate-90' : ''}`} />
            </button>

            {isMenuOpen && (
              <div className="absolute top-full left-0 mt-2 w-48 glass rounded-2xl p-2 animate-in fade-in slide-in-from-top-4 duration-300 shadow-2xl border border-white/10">
                <button 
                  onClick={() => { setIsContactOpen(true); setIsMenuOpen(false); }}
                  className="w-full text-left px-4 py-2 rounded-xl hover:bg-white/10 flex items-center gap-3 text-xs font-bold transition-all"
                >
                  <i className="fas fa-envelope text-orange-500" /> Contact Us
                </button>
                {user && (
                   <button 
                   onClick={() => { setUser(null); localStorage.removeItem('rx_user'); setIsMenuOpen(false); }}
                   className="w-full text-left px-4 py-2 rounded-xl hover:bg-red-500/20 text-red-400 flex items-center gap-3 text-xs font-bold transition-all"
                 >
                   <i className="fas fa-sign-out-alt" /> Logout
                 </button>
                )}
              </div>
            )}
          </div>

          {/* Login/User Button */}
          <button 
            onClick={() => user ? null : setIsLoginOpen(true)}
            className={`px-3 sm:px-5 h-10 sm:h-11 glass rounded-2xl flex items-center gap-2 font-black text-[10px] sm:text-xs uppercase tracking-widest transition-all duration-300 shadow-xl ${user ? 'border-green-500/50 text-green-400' : 'hover:scale-105 active:scale-95 hover:bg-white/10'}`}
          >
            <i className={`fas ${user ? 'fa-user-check' : 'fa-user'} ${user ? 'animate-bounce' : ''}`} />
            {user ? user.nickname : 'Login'}
          </button>
        </div>

        {/* View Switcher */}
        <button 
          onClick={toggleView}
          className="h-10 sm:h-11 px-3 sm:px-5 glass rounded-2xl flex items-center gap-2 font-black text-[10px] sm:text-xs uppercase tracking-widest hover:scale-105 active:scale-95 transition-all duration-300 shadow-xl hover:bg-white/10"
        >
          <i className="fas fa-magic text-cyan-400" />
