import React, { useState, useEffect, useCallback, useRef } from 'react';
import ReactDOM from 'react-dom/client';
import { GoogleGenAI } from "@google/genai";

// --- CONSTANTS & TYPES ---
const OPENWEATHER_API_KEY = "bd9768a3c377f6b1b0546c376b794ab6";
const BASE_URL_OWM = "https://api.openweathermap.org/data/2.5/";

interface WeatherData {
  name: string;
  coord: { lat: number; lon: number };
  main: { temp: number; feels_like: number; temp_min: number; temp_max: number; pressure: number; humidity: number };
  wind: { speed: number; gust?: number };
  weather: Array<{ description: string; icon: string; main: string }>;
  sys: { country: string; sunrise: number; sunset: number };
  timezone: number;
}

interface ForecastItem {
  dt: number;
  main: { temp: number; humidity: number };
  weather: Array<{ description: string; icon: string }>;
  wind: { speed: number };
  pop: number;
}

interface ForecastData { list: ForecastItem[]; }

interface AQIData {
  aqi: number;
  components: { pm2_5: number; pm10: number; no2: number; o3: number; so2: number };
}

interface User { nickname: string; email: string; }
type ViewMode = 'auto' | 'mobile' | 'pc';

// --- SERVICES ---
const fetchWeatherByCity = async (city: string): Promise<WeatherData> => {
  const res = await fetch(`${BASE_URL_OWM}weather?units=metric&q=${city}&appid=${OPENWEATHER_API_KEY}`);
  if (!res.ok) throw new Error("City not found");
  return res.json();
};

const fetchWeatherByCoords = async (lat: number, lon: number): Promise<WeatherData> => {
  const res = await fetch(`${BASE_URL_OWM}weather?units=metric&lat=${lat}&lon=${lon}&appid=${OPENWEATHER_API_KEY}`);
  if (!res.ok) throw new Error("Location not found");
  return res.json();
};

const fetchForecast = async (lat: number, lon: number): Promise<ForecastData> => {
  const res = await fetch(`${BASE_URL_OWM}forecast?units=metric&lat=${lat}&lon=${lon}&appid=${OPENWEATHER_API_KEY}`);
  if (!res.ok) throw new Error("Forecast unavailable");
  return res.json();
};

const fetchAQI = async (lat: number, lon: number): Promise<AQIData> => {
  const res = await fetch(`${BASE_URL_OWM}air_pollution?lat=${lat}&lon=${lon}&appid=${OPENWEATHER_API_KEY}`);
  if (!res.ok) throw new Error("AQI unavailable");
  const data = await res.json();
  return { aqi: data.list[0].main.aqi, components: data.list[0].components };
};

const fetchUVIndex = async (lat: number, lon: number): Promise<number> => {
  const res = await fetch(`${BASE_URL_OWM}uvi?lat=${lat}&lon=${lon}&appid=${OPENWEATHER_API_KEY}`);
  if (!res.ok) return 0;
  const data = await res.json();
  return data.value;
};

const getWeatherInsight = async (weather: WeatherData, aqi: AQIData, uv: number): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `Weather in ${weather.name}: ${weather.weather[0].description}, ${Math.round(weather.main.temp)}°C. AQI: ${aqi.aqi}, UV: ${uv}. Summarize in 2 sentences with 1 tip.`;
  try {
    const res = await ai.models.generateContent({ model: 'gemini-3-flash-preview', contents: prompt });
    return res.text || "Enjoy the clear skies today!";
  } catch { return "The weather looks promising. Stay hydrated!"; }
};

