const MapDisplay: React.FC<{ lat: number; lon: number; cityName: string }> = ({ lat, lon, cityName }) => {
  const mapRef = useRef<any>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  useEffect(() => {
    if (!containerRef.current) return;
    if (!mapRef.current) {
      // @ts-ignore
      mapRef.current = L.map(containerRef.current, { zoomControl: false, attributionControl: false }).setView([lat, lon], 10);
      // @ts-ignore
      L.tileLayer('https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}').addTo(mapRef.current);
    } else {
      mapRef.current.flyTo([lat, lon], 10);
    }
  }, [lat, lon]);
  return (
    <div className="relative w-full h-full rounded-3xl overflow-hidden border border-white/10 mt-6 shadow-2xl">
      <div ref={containerRef} className="w-full h-full" />
      <div className="absolute top-3 left-3 bg-black/60 backdrop-blur-md px-3 py-1 rounded-lg text-[8px] font-black uppercase tracking-widest border border-white/10 z-[400]">
        <span className="w-1.5 h-1.5 bg-orange-500 rounded-full inline-block mr-2 animate-pulse" />
        {cityName} RADAR
      </div>
    </div>
  );
};

