  const [isContactOpen, setIsContactOpen] = useState(false);

  const [searchQuery, setSearchQuery] = useState('');
  const [weather, setWeather] = useState<WeatherData | null>(null);
  const [forecast, setForecast] = useState<ForecastData | null>(null);
  const [aqi, setAqi] = useState<AQIData | null>(null);
  const [uv, setUv] = useState<number | null>(null);
  const [aiInsight, setAiInsight] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [user, setUser] = useState<User | null>(() => {
    const s = localStorage.getItem('rx_user');
    return s ? JSON.parse(s) : null;
  });
  const [history, setHistory] = useState<string[]>(() => {
    const s = localStorage.getItem('rx_history');
    return s ? JSON.parse(s) : [];
  });
  const [showHistory, setShowHistory] = useState(false);
  const [now, setNow] = useState(new Date());

  useEffect(() => {
    const t = setInterval(() => setNow(new Date()), 1000);
    return () => clearInterval(t);
  }, []);

  const handleSearch = useCallback(async (q: string) => {
    if (!q) return;
    setLoading(true); setError(null); setShowHistory(false);
    try {
      const w = await fetchWeatherByCity(q);
      const [f, a, u] = await Promise.all([
        fetchForecast(w.coord.lat, w.coord.lon),
        fetchAQI(w.coord.lat, w.coord.lon),
        fetchUVIndex(w.coord.lat, w.coord.lon)
      ]);
      setWeather(w); setForecast(f); setAqi(a); setUv(u);
      getWeatherInsight(w, a, u).then(setAiInsight);
      if (user) {
        setHistory(prev => {
          const u = [w.name, ...prev.filter(i => i !== w.name)].slice(0, 5);
          localStorage.setItem('rx_history', JSON.stringify(u));
          return u;
        });
      }
    } catch (err: any) { setError(err.message); } finally { setLoading(false); }
  }, [user]);

  const handleLocationSearch = () => {
    if (!navigator.geolocation) return;
    setLoading(true);
    navigator.geolocation.getCurrentPosition(async p => {
      try {
        const w = await fetchWeatherByCoords(p.coords.latitude, p.coords.longitude);
        const [f, a, u] = await Promise.all([fetchForecast(w.coord.lat, w.coord.lon), fetchAQI(w.coord.lat, w.coord.lon), fetchUVIndex(w.coord.lat, w.coord.lon)]);
        setWeather(w); setForecast(f); setAqi(a); setUv(u);
        getWeatherInsight(w, a, u).then(setAiInsight);
      } catch (err: any) { setError(err.message); } finally { setLoading(false); }
    }, () => { setLoading(false); setError("Permission denied"); });
  };

  useEffect(() => { handleSearch("Kathmandu"); }, []);

  const formatSun = (ts: number, off: number) => {
    const d = new Date((ts + off) * 1000);
    return d.getUTCHours().toString().padStart(2, '0') + ":" + d.getUTCMinutes().toString().padStart(2, '0');
  };

  return (
    <div className={`min-h-screen py-6 sm:py-10 px-4 flex flex-col items-center justify-start transition-all duration-500 ${viewMode === 'mobile' ? 'max-w-md mx-auto' : 'w-full'}`}>
      <Background />

      <div className="w-full max-w-2xl flex items-center justify-between mb-4 z-50">
        <div className="flex gap-2">
          <div className="relative">
            <button onClick={() => setIsMenuOpen(!isMenuOpen)} className="w-10 h-10 glass rounded-xl flex items-center justify-center hover:bg-orange-600 transition-all"><i className="fas fa-ellipsis-v text-xs" /></button>
            {isMenuOpen && (
              <div className="absolute top-full left-0 mt-2 w-40 glass rounded-xl p-2 shadow-2xl z-[60]">
                <button onClick={() => {setIsContactOpen(true); setIsMenuOpen(false);}} className="w-full text-left px-3 py-2 rounded-lg hover:bg-white/10 text-[10px] font-bold uppercase"><i className="fas fa-envelope mr-2 text-orange-500" /> Contact</button>
                {user && <button onClick={() => {setUser(null); localStorage.removeItem('rx_user'); setIsMenuOpen(false);}} className="w-full text-left px-3 py-2 rounded-lg hover:bg-red-500/20 text-red-400 text-[10px] font-bold uppercase"><i className="fas fa-sign-out-alt mr-2" /> Logout</button>}
              </div>
            )}
          </div>
          <button onClick={() => !user && setIsLoginOpen(true)} className={`px-4 h-10 glass rounded-xl flex items-center gap-2 font-black text-[10px] uppercase tracking-widest ${user ? 'text-green-400' : ''}`}>
            <i className={`fas ${user ? 'fa-user-check' : 'fa-user'}`} /> {user ? user.nickname : 'Login'}
          </button>
        </div>
        <button onClick={() => setViewMode(prev => prev === 'mobile' ? 'pc' : 'mobile')} className="h-10 px-4 glass rounded-xl flex items-center gap-2 font-black text-[10px] uppercase tracking-widest"><i className="fas fa-magic text-cyan-400" /> {viewMode}</button>
      </div>

      <div className="glass w-full max-w-2xl rounded-[32px] sm:rounded-[40px] shadow-2xl overflow-hidden animate-in zoom-in-95">
        <div className="bg-black/20 p-4 sm:p-6 flex justify-between items-center border-b border-white/5">
          <div className="flex items-center gap-2 text-xs sm:text-lg font-black tracking-widest uppercase"><i className="fas fa-cloud-sun text-orange-500" /> RX WEATHER</div>
          <div className="text-right">
            <div className="text-[8px] sm:text-[10px] font-bold opacity-40 uppercase">{now.toLocaleDateString([], { weekday: 'short', month: 'short', day: 'numeric' })}</div>
            <div className="text-xs sm:text-xl font-bold font-mono">{now.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</div>
          </div>
        </div>

        <div className="p-4 sm:p-8 relative">
          <div className="flex gap-1.5 p-1 bg-white/5 border border-white/10 rounded-full focus-within:bg-black/30 transition-all">
            <input placeholder="Search city..." className="bg-transparent flex-1 px-4 outline-none text-sm placeholder:opacity-30" value={searchQuery} onChange={e => setSearchQuery(e.target.value)} onFocus={() => setShowHistory(true)} onKeyDown={e => e.key === 'Enter' && handleSearch(searchQuery)} />
            <button onClick={() => weather && handleSearch(weather.name)} className="w-8 h-8 sm:w-10 sm:h-10 rounded-full hover:bg-blue-500/20 text-blue-400 flex items-center justify-center"><i className={`fas fa-sync-alt text-[10px] ${loading ? 'animate-spin' : ''}`} /></button>
            <button onClick={handleLocationSearch} className="w-8 h-8 sm:w-10 sm:h-10 rounded-full hover:bg-green-500/20 text-green-400 flex items-center justify-center"><i className="fas fa-location-arrow text-[10px]" /></button>
            <button onClick={() => handleSearch(searchQuery)} className="w-8 h-8 sm:w-10 sm:h-10 bg-orange-600 rounded-full flex items-center justify-center hover:scale-110 active:scale-95 transition-all"><i className="fas fa-search text-[10px]" /></button>
          </div>
          {showHistory && user && history.length > 0 && (
            <div className="absolute top-16 left-6 right-6 glass rounded-2xl p-1 z-40 animate-in fade-in">
              {history.map((h, i) => <button key={i} onClick={() => {setSearchQuery(h); handleSearch(h);}} className="w-full text-left px-4 py-2 rounded-xl hover:bg-white/10 text-[10px] font-bold opacity-60 flex items-center gap-2"><i className="fas fa-history text-[8px]" /> {h}</button>)}
            </div>
          )}
        </div>

        <div className="px-4 sm:px-8 pb-8">
          {error && <div className="bg-red-500/20 border-l-4 border-red-500 p-3 rounded-xl mb-4 text-[10px] font-bold uppercase">{error}</div>}
          {weather && !loading ? (
            <div className="animate-in fade-in slide-in-from-bottom-4">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6 items-center border-b border-white/10 pb-6">
                <div className="flex flex-col">
                  <div className="flex items-center gap-2">
                    <img src={`https://openweathermap.org/img/wn/${weather.weather[0].icon}@4x.png`} className="w-20 h-20 animate-float" alt="icon" />
                    <div>
                      <div className="text-5xl font-bold tracking-tighter">{Math.round(weather.main.temp)}<span className="text-2xl font-light align-top ml-1">°C</span></div>
                      <div className="text-[10px] font-black opacity-40 uppercase tracking-widest">Feels like {Math.round(weather.main.feels_like)}°</div>
                    </div>
                  </div>
                  <div className="text-lg font-black mt-2 flex items-center gap-2 tracking-tight"><i className="fas fa-map-marker-alt text-orange-500" /> {weather.name}, {weather.sys.country}</div>
                </div>
                <div className="grid grid-cols-2 gap-2">
                  {[
                    { label: "Humidity", val: `${weather.main.humidity}%` },
                    { label: "UV Index", val: Math.round(uv || 0) },
                    { label: "Sunrise", val: <span className="flex items-center gap-1.5"><i className="fas fa-sun text-yellow-400 text-[8px]" /> {formatSun(weather.sys.sunrise, weather.timezone)}</span> },
                    { label: "Sunset", val: <span className="flex items-center gap-1.5"><i className="fas fa-cloud-sun text-orange-400 text-[8px]" /> {formatSun(weather.sys.sunset, weather.timezone)}</span> },
                  ].map((d, i) => (
                    <div key={i} className="flex flex-col p-2 bg-white/5 rounded-xl border border-white/5">
                      <span className="text-[8px] opacity-40 font-black uppercase mb-1">{d.label}</span>
                      <span className="text-[10px] font-bold">{d.val}</span>
                    </div>
                  ))}
                </div>
              </div>

              {aiInsight && (
                <div className="mt-6 p-4 bg-gradient-to-r from-blue-600/10 to-purple-600/10 border border-white/10 rounded-2xl flex items-start gap-3">
                  <div className="w-8 h-8 bg-blue-600/20 rounded-lg flex items-center justify-center shrink-0"><i className="fas fa-robot text-blue-400 text-xs" /></div>
                  <div className="text-[10px] font-medium leading-relaxed italic">
                    <span className="font-black text-blue-300 not-italic block mb-1 text-[8px] uppercase tracking-widest">Atmospheric Insight</span> "{aiInsight}"
                  </div>
                </div>
              )}

              <div className="grid grid-cols-3 gap-2 mt-6">
                {['Hourly', 'Daily', 'AQI'].map((b, i) => (
                  <button key={i} onClick={() => { if(b==='Hourly') setIsHourlyOpen(true); else if(b==='Daily') setIsDailyOpen(true); else setIsAQIOpen(true); }} className="glass py-2.5 rounded-xl text-[8px] font-black uppercase tracking-widest hover:bg-orange-600 active:scale-95 transition-all">{b}</button>
                ))}
              </div>

              <div className="h-48 sm:h-72 mt-6"><MapDisplay lat={weather.coord.lat} lon={weather.coord.lon} cityName={weather.name} /></div>
            </div>
          ) : (
            <div className="py-20 flex flex-col items-center gap-4">
              <div className="w-10 h-10 border-2 border-orange-500/20 border-t-orange-500 rounded-full animate-spin" />
              <p className="text-[8px] font-black uppercase tracking-[0.3em] opacity-30 animate-pulse">Establishing uplink...</p>
            </div>
          )}
        </div>
        <div className="bg-black/30 p-6 text-center border-t border-white/5">
          <div className="text-[10px] opacity-40 font-bold uppercase tracking-widest">© 2026 RX Weather • Engineered by Aman</div>
        </div>
      </div>

      <LoginModal isOpen={isLoginOpen} onClose={() => setIsLoginOpen(false)} onLogin={u => {setUser(u); localStorage.setItem('rx_user', JSON.stringify(u)); setIsLoginOpen(false);}} />
      {forecast && (
        <>
          <ForecastModal isOpen={isHourlyOpen} onClose={() => setIsHourlyOpen(false)} items={forecast.list.slice(0, 8)} title="Next 24 Hours" type="hourly" />
          <ForecastModal isOpen={isDailyOpen} onClose={() => setIsDailyOpen(false)} items={forecast.list.filter((_, i) => i % 8 === 0)} title="5-Day Outlook" type="daily" />
        </>
      )}
      {isContactOpen && (
        <div className="fixed inset-0 z-[200] flex animate-in slide-in-from-left duration-500">
          <div className="w-64 h-full glass p-10 flex flex-col justify-center relative border-r border-white/10">
            <button onClick={() => setIsContactOpen(false)} className="absolute top-6 right-6 text-2xl opacity-40">&times;</button>
            <h2 className="text-2xl font-black mb-1 tracking-tighter uppercase">Support</h2>
            <p className="text-[10px] font-medium mb-8 opacity-40 uppercase">24/7 Assistance</p>
            <div className="bg-white/5 p-4 rounded-xl border border-white/10 mb-4 font-mono text-[9px]">sdfre3511@gmail.com</div>
            <button onClick={() => {navigator.clipboard.writeText("sdfre3511@gmail.com"); alert("Copied!");}} className="bg-white text-slate-950 py-3 rounded-xl font-black uppercase text-[10px] tracking-widest">Copy Email</button>
          </div>
          <div className="flex-1 bg-black/40 backdrop-blur-sm" onClick={() => setIsContactOpen(false)} />
        </div>
      )}
    </div>
  );
};

