const ForecastModal: React.FC<{ isOpen: boolean; onClose: () => void; title: string; items: ForecastItem[]; type: 'hourly' | 'daily' }> = ({ isOpen, onClose, title, items, type }) => {
  if (!isOpen) return null;
  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/70 backdrop-blur-md animate-in fade-in">
      <div className="glass w-full max-w-3xl rounded-[40px] p-8 max-h-[85vh] flex flex-col overflow-hidden relative shadow-2xl">
        <div className="flex justify-between items-center mb-8 border-b border-white/5 pb-6">
          <h2 className="text-2xl font-black uppercase tracking-tighter text-orange-500">{title}</h2>
          <button onClick={onClose} className="w-10 h-10 rounded-full bg-white/5 flex items-center justify-center hover:bg-red-500/20 text-2xl transition-all">&times;</button>
        </div>
        <div className="overflow-y-auto grid grid-cols-2 sm:grid-cols-4 gap-4 custom-scrollbar p-1">
          {items.map((item, idx) => (
            <div key={idx} className="bg-white/5 rounded-3xl p-6 flex flex-col items-center text-center border border-white/5 hover:bg-white/10 transition-all group">
              <span className="text-xs font-black opacity-40 uppercase mb-3 group-hover:text-orange-400 transition-colors">
                {type === 'daily' ? new Date(item.dt * 1000).toLocaleDateString('en-US', { weekday: 'short' }) : new Date(item.dt * 1000).toLocaleTimeString([], { hour: 'numeric' })}
              </span>
              <img src={`https://openweathermap.org/img/wn/${item.weather[0].icon}@2x.png`} className="w-14 h-14 group-hover:scale-110 transition-transform" alt="icon" />
              <span className="text-2xl font-black mt-2">{Math.round(item.main.temp)}°</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

const MapDisplay: React.FC<{ lat: number; lon: number; cityName: string }> = ({ lat, lon, cityName }) => {
  const mapRef = useRef<any>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!containerRef.current) return;
    if (!mapRef.current) {
      // @ts-ignore
      mapRef.current = L.map(containerRef.current, { zoomControl: false, attributionControl: false }).setView([lat, lon], 10);

      // Satellite Imagery Layer
      // @ts-ignore
      L.tileLayer('https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}').addTo(mapRef.current);

      // Place Names & Boundaries Layer (Overlay)
      // @ts-ignore
      L.tileLayer('https://server.arcgisonline.com/ArcGIS/rest/services/Reference/World_Boundaries_and_Places/MapServer/tile/{z}/{y}/{x}', {
        opacity: 0.8
      }).addTo(mapRef.current);

    } else {
      mapRef.current.flyTo([lat, lon], 11, { duration: 2 });
    }
  }, [lat, lon]);

  return (
    <div className="relative w-full h-full rounded-[32px] overflow-hidden border border-white/10 mt-8 shadow-2xl group">
      <div ref={containerRef} className="w-full h-full grayscale-[0.2] group-hover:grayscale-0 transition-all duration-700" />
      <div className="absolute top-4 left-4 bg-black/60 backdrop-blur-md px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest border border-white/10 z-[400] flex items-center gap-3">
        <span className="w-2 h-2 bg-orange-500 rounded-full inline-block animate-pulse" />
        {cityName} LIVE RADAR
      </div>
      <div className="absolute bottom-4 right-4 bg-orange-600/80 backdrop-blur-md px-3 py-1 rounded-lg text-[8px] font-bold uppercase z-[400] opacity-0 group-hover:opacity-100 transition-opacity">
        ArcGIS Satellite Data
      </div>
    </div>
  );
};

// --- MAIN APP ---

const App: React.FC = () => {
  const [viewMode, setViewMode] = useState<ViewMode>('auto');
  const [isLoginOpen, setIsLoginOpen] = useState(false);
  const [isHourlyOpen, setIsHourlyOpen] = useState(false);
  const [isDailyOpen, setIsDailyOpen] = useState(false);
  const [isAQIOpen, setIsAQIOpen] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isContactOpen, setIsContactOpen] = useState(false);

  const [searchQuery, setSearchQuery] = useState('');
  const [weather, setWeather] = useState<WeatherData | null>(null);
  const [forecast, setForecast] = useState<ForecastData | null>(null);
  const [aqi, setAqi] = useState<AQIData | null>(null);
  const [uv, setUv] = useState<number | null>(null);
  const [aiInsight, setAiInsight] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [user, setUser] = useState<User | null>(() => {
    const s = localStorage.getItem('rx_user');
    return s ? JSON.parse(s) : null;
  });
  const [history, setHistory] = useState<string[]>(() => {
    const s = localStorage.getItem('rx_history');
    return s ? JSON.parse(s) : [];
  });
  const [showHistory, setShowHistory] = useState(false);
  const [now, setNow] = useState(new Date());

  useEffect(() => {
    const t = setInterval(() => setNow(new Date()), 1000);
    return () => clearInterval(t);
  }, []);

  const handleSearch = useCallback(async (q: string) => {
    if (!q) return;
    setLoading(true); setError(null); setShowHistory(false);
    try {
      const w = await fetchWeatherByCity(q);
      const [f, a, u] = await Promise.all([
        fetchForecast(w.coord.lat, w.coord.lon),
        fetchAQI(w.coord.lat, w.coord.lon),
        fetchUVIndex(w.coord.lat, w.coord.lon)
      ]);
