}

export interface GroundingLink {
  title: string;
  uri: string;
}

export interface ForecastItem {
  dt: number;
  main: { temp: number; humidity: number };
  weather: Array<{ description: string; icon: string }>;
  wind: { speed: number };
  pop: number;
}

export interface ForecastData {
  list: ForecastItem[];
}

export interface AQIData {
  aqi: number;
  components: {
    pm2_5: number;
    pm10: number;
    no2: number;
    o3: number;
    so2: number;
  };
}

