import { GoogleGenAI } from "@google/genai";
import { WeatherData, AQIData, GroundingLink } from "../types";

export interface WeatherInsightResult {
  text: string;
  links: GroundingLink[];
}

export const getWeatherInsight = async (
  weather: WeatherData, 
  aqi: AQIData, 
  uv: number,
  lat: number,
  lon: number
): Promise<WeatherInsightResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Analyze the current weather, air quality, and UV index for ${weather.name}, ${weather.sys.country}.
    Coordinates: ${lat}, ${lon}.
    Weather: ${weather.weather[0].description}, Temp: ${Math.round(weather.main.temp)}°C, Humidity: ${weather.main.humidity}%.
    Air Quality Index: ${aqi.aqi}.
    UV Index: ${uv}.
    Using your knowledge of this specific area and its geography from Google Maps, 
    provide a concise, friendly 2-sentence summary and 1 practical recommendation 
    for outdoor activities. Mention if there are any specific local landmarks or 
    geographic features that might be affected by these conditions.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: {
          retrievalConfig: {
            latLng: {
              latitude: lat,
              longitude: lon
            }
          }
        }
      },
    });

    const text = response.text || "No insights available at the moment.";
    const links: GroundingLink[] = [];

    // Extract Google Maps grounding chunks as required by guidelines
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (chunks) {
      chunks.forEach((chunk: any) => {
        if (chunk.maps) {
          links.push({
            title: chunk.maps.title || "View on Google Maps",
            uri: chunk.maps.uri
          });
        }
      });
    }

    return { text, links };
  } catch (error) {
    console.error("Gemini Error:", error);
    return { 
      text: "The sky is the limit! Enjoy your day and check local conditions.",
      links: []
    };
  }
};

