import { GoogleGenAI } from "@google/genai";
import { WeatherData, AQIData, GroundingLink } from "../types";

export interface WeatherInsightResult {
  text: string;
  links: GroundingLink[];
}

export const getWeatherInsight = async (
  weather: WeatherData, 
  aqi: AQIData, 
  uv: number,
  lat: number,
  lon: number
): Promise<WeatherInsightResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Analyze the current weather, air quality, and UV index for ${weather.name}, ${weather.sys.country} at coordinates ${lat}, ${lon}.

    Current Stats:
    - Condition: ${weather.weather[0].description}
    - Temp: ${Math.round(weather.main.temp)}°C (Feels like ${Math.round(weather.main.feels_like)}°C)
    - Humidity: ${weather.main.humidity}%
    - AQI: ${aqi.aqi}
    - UV Index: ${uv}

    As a local weather expert with real-time access to Google Maps:
    1. Write a 2-sentence highly descriptive summary of how the weather "feels" in this specific terrain (mention local landmarks or geography if relevant).
    2. Provide 3 bulleted "Expert Recommendations" for the next 4 hours (e.g., best parks to visit, what to wear, or safety precautions).

    Format your response in clean Markdown. Use bolding for emphasis. Do not use JSON.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: {
          retrievalConfig: {
            latLng: {
              latitude: lat,
              longitude: lon
            }
          }
        }
      },
    });

    const text = response.text || "No insights available at the moment.";
    const links: GroundingLink[] = [];

    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (chunks) {
      chunks.forEach((chunk: any) => {
        if (chunk.maps) {
          links.push({
            title: chunk.maps.title || "View Location",
            uri: chunk.maps.uri
          });
        }
      });
    }

    return { text, links };
  } catch (error) {
    console.error("Gemini Error:", error);
    return { 
      text: "The sky is the limit! Enjoy your day and check local conditions.",
      links: []
    };
  }
};

